// Auto-generated: quiz content for Cours17 — translations can be added per-locale.
// Structural data arrays (DEGREES, MODES, etc.) remain in the component for now.

export interface Question { q: string; opts: string[]; a: number; fb: string; }
export interface Cours17Locale { questions: Question[]; }

const questionsFr: Question[] = [
  // Motif
  { q: "Qu'est-ce qu'un motif musical ?", opts: ["Un accord de 4 sons", "Le plus petit élément musical distinctif — fil conducteur du discours d'une phrase", "Une gamme complète", "Un accord de dominante"], a: 1, fb: "Le motif est le plus petit élément musical reconnaissable et structurant. Il contient l'identité rythmique et/ou mélodique qui sera répétée et transformée. Beethoven construit toute sa 5e Symphonie à partir d'un motif de 4 notes seulement (Sol–Sol–Sol–Mib)." },
  { q: "Le motif de la 5e Symphonie de Beethoven (Sol–Sol–Sol–Mib) illustre que :", opts: ["Un motif doit être long pour être expressif", "Un motif extrêmement court peut générer un discours musical complet par répétition et transformation", "La 5e utilise un mode mineur exclusivement", "Ce motif vient d'une chanson populaire"], a: 1, fb: "Sol–Sol–Sol–Mib : 4 notes, 3 répétées + une chute de tierce. Ce motif est le germe de toute la 5e Symphonie (1808). Beethoven le fragmente, le transpose, l'augmente — démontrant qu'un motif minimal peut construire vingt minutes de musique." },
  { q: "Quelle différence entre 'musique de support' et 'musique de discours' ?", opts: ["La musique de support est plus longue", "La musique de support accompagne une action extérieure ; la musique de discours développe ses propres idées musicales de façon autonome", "La musique de discours est plus courte", "Il n'y a aucune différence"], a: 1, fb: "La musique de support (film, ballet) sert une action extérieure — sa structure peut être fragmentée selon la narration. La musique de discours (sonate, fugue, standard jazz) développe ses propres idées de façon logique et autonome, indépendamment de tout contexte extra-musical." },
  { q: "Le fil conducteur d'une phrase musicale est :", opts: ["La tonalité", "Le motif — répété et transformé pour donner cohérence à la phrase", "Le tempo", "L'accompagnement"], a: 1, fb: "Le motif est le fil conducteur. Sa répétition (stricte ou transformée) crée la cohérence. L'auditeur reconnaît le motif même transformé — c'est ce qui donne l'impression d'un discours musical suivi plutôt qu'une succession d'idées disparates." },

  // Les 4 étapes
  { q: "Combien d'étapes comporte une phrase musicale typique de 8 mesures ?", opts: ["2", "3", "4", "8"], a: 2, fb: "La phrase de 8 mesures suit 4 étapes : (1) idée de base, (2) répétition, (3) accélération/fragmentation, (4) cadence. Ce schéma est présent chez Beethoven, Mozart, Haydn et dans la plupart des formes jazz standard." },
  { q: "Quelle est la première étape d'une phrase musicale ?", opts: ["La cadence", "L'idée de base — présentation du motif principal", "La répétition", "La liquidation"], a: 1, fb: "L'idée de base est l'énoncé du 'sujet' de la phrase : présentation du motif ou de la cellule motivique. Les 3 étapes suivantes (répétition, accélération, cadence) découlent de cette idée initiale." },
  { q: "Qu'est-ce que la 'liquidation' d'une phrase (terme de Schoenberg) ?", opts: ["Répéter le motif plus lentement", "Accélérer le rythme harmonique en fin de phrase — les harmonies changent plus vite pour signaler la cadence imminente", "Réduire le nombre d'instruments", "Jouer moins fort"], a: 1, fb: "La liquidation désigne l'accélération du rythme harmonique en fin de phrase. Les harmonies qui changeaient toutes les 2 mesures changent maintenant toutes les mesures, puis à chaque temps — signal rhétorique que la cadence approche : 'la conclusion arrive'." },
  { q: "Dans la 3e étape d'une phrase de Beethoven, l'accélération se manifeste par :", opts: ["Un tempo plus rapide", "Des motifs fragmentés et un rythme harmonique plus dense, créant tension avant la cadence", "Un changement d'instrument", "Une mélodie plus grave"], a: 1, fb: "L'accélération de la 3e étape = fragmentation du motif et densification du rythme harmonique. Beethoven répète des fragments de motif de plus en plus courts, les accords changent de plus en plus vite — tension qui 'appelle' la cadence finale." },

  // Techniques de répétition
  { q: "Qu'est-ce que la 'répétition stricte' d'un motif ?", opts: ["Répéter dans une autre tonalité", "Répéter le motif identiquement — mêmes hauteurs, même rythme", "Répéter avec des ornements", "Répéter uniquement à l'octave inférieure"], a: 1, fb: "La répétition stricte reproduit le motif exactement. Technique la plus directe : l'auditeur reconnaît immédiatement le motif. Elle peut sembler mécanique ; c'est pourquoi elle est souvent combinée avec d'autres techniques de transformation." },
  { q: "La 'transformation mélodique' d'un motif consiste à :", opts: ["Changer son rythme", "Transposer le motif à une autre hauteur tout en gardant le même contour rythmique", "Inverser les intervalles", "Jouer le motif à l'envers"], a: 1, fb: "La transformation mélodique transpose le motif — le contour rythmique reste identique, les hauteurs changent. Do–Mi–Sol devient Ré–Fa–La (un ton plus haut). L'identité rythmique maintient la cohérence ; la nouvelle hauteur apporte la variété." },
  { q: "Une 'marche' (ou séquence) musicale est :", opts: ["Un rythme de marche militaire", "Un motif répété à des degrés successifs de la gamme ou par transposition chromatique", "Un accord de passage", "Une forme de 16 mesures"], a: 1, fb: "La marche (séquence) répète un motif à des hauteurs successives. Marche tonale : reste dans la gamme diatonique. Marche réelle (chromatique) : transpose strictement le même intervalle (peut sortir de la gamme). Ex. Do–Mi–Sol, Ré–Fa–La, Mi–Sol–Si (marche tonale ascendante)." },
  { q: "La différence entre 'marche tonale' et 'marche réelle' est :", opts: ["Le tempo", "La marche tonale reste diatonique (intervalles légèrement ajustés) ; la marche réelle transpose strictement le même intervalle, créant des chromatismes", "La marche réelle est plus longue", "Il n'y a aucune différence"], a: 1, fb: "Distinction clé de Schoenberg : marche tonale = le motif s'adapte aux intervalles de la gamme (peut changer légèrement d'intervalle) ; marche réelle = transposition stricte du même intervalle (peut introduire des notes étrangères à la gamme)." },
  { q: "Un motif 'complémentaire' est :", opts: ["Un motif qui imite le principal à l'unisson", "Un second motif qui répond au premier, complétant l'espace rythmique ou mélodique de la phrase", "Un motif inversé", "Un motif joué simultanément"], a: 1, fb: "Le motif complémentaire répond au motif principal — souvent dans les mesures suivantes. Ex. Motif A (mesures 1–2) + Motif B (mesures 3–4). Ensemble, A et B forment la phrase complète ; chacun est incomplet sans l'autre." },
  { q: "La 'transformation mélodico-harmonique' consiste à :", opts: ["Changer le rythme et la mélodie", "Garder le contour mélodique du motif mais changer les accords en dessous, modifiant la couleur harmonique", "Inverser la mélodie et les accords", "Transposer dans 12 tonalités"], a: 1, fb: "La transformation mélodico-harmonique conserve le contour mélodique reconnaissable mais change les accords en dessous. La mélodie Do–Mi–Sol sonnera différemment sur I (CMaj7) que sur VI (Am7). La mélodie crée la cohérence ; l'harmonie renouvelle l'expression." },

  // Période antécédent-conséquent
  { q: "Qu'est-ce qu'une période musicale ?", opts: ["Une phrase de 4 mesures", "Une structure en deux phrases : antécédent (cadence faible) + conséquent (cadence forte)", "Un groupe de 3 phrases", "Une section de 32 mesures"], a: 1, fb: "La période est binaire : l'antécédent (phrase 1) se termine sur une cadence faible (souvent V — demi-cadence), créant une question. Le conséquent (phrase 2) se termine sur une cadence forte (I — cadence parfaite), apportant la réponse. Longueur typique : 16 mesures (8+8)." },
  { q: "L'antécédent d'une période se termine sur :", opts: ["La tonique (I) — cadence parfaite", "La dominante (V) — demi-cadence, effet de question suspendue", "La sous-dominante (IV)", "La médiante (III)"], a: 1, fb: "L'antécédent se termine sur V (demi-cadence) — l'oreille attend une conclusion. C'est la 'question'. Le conséquent répond en terminant sur I. Ce schéma question/réponse est la structure rhétorique fondamentale de la musique tonale." },
  { q: "Le conséquent d'une période se termine sur :", opts: ["La dominante (V)", "La tonique (I) — cadence parfaite, conclusion", "La sous-dominante (IV)", "Un accord de septième"], a: 1, fb: "Le conséquent se termine sur I (cadence parfaite). Après la 'question' de l'antécédent (qui finit sur V), le conséquent apporte la 'réponse' conclusive en s'ancrant sur la tonique. C'est la rhétorique musicale la plus naturelle." },
  { q: "La différence principale entre une phrase et une période est :", opts: ["La longueur uniquement", "La phrase = une unité autonome (8 mes.) avec sa cadence ; la période = deux phrases (antécédent + conséquent, 16 mes.) avec cadence faible puis forte", "Le nombre de motifs", "La tonalité"], a: 1, fb: "La phrase est une unité autonome (typiquement 8 mesures) avec sa propre cadence. La période est une structure de deux phrases : antécédent (cadence V — question) + conséquent (cadence I — réponse). La période fait donc typiquement 16 mesures." },
  { q: "Antécédent et conséquent partagent souvent :", opts: ["Exactement les mêmes notes", "Le même matériel thématique de départ — liés par un même motif initial, mais conclus différemment", "Le même tempo", "La même durée absolument"], a: 1, fb: "Antécédent et conséquent commencent souvent avec le même motif — c'est ce qui les unit en une période cohérente. Mais leurs fins diffèrent : cadence V (antécédent) vs cadence I (conséquent). Même début, conclusions contrastantes : question/réponse." },
  { q: "L'effet de 'question/réponse' dans une période est créé par :", opts: ["Deux motifs différents", "La cadence faible de l'antécédent (V) qui crée l'attente, résolue par la cadence forte du conséquent (I)", "Le changement de tempo", "L'augmentation du volume"], a: 1, fb: "V (demi-cadence) = question suspendue. I (cadence parfaite) = réponse conclusive. Ce schéma question/réponse à l'échelle de la période reflète la même logique que la tension/résolution à l'échelle de l'accord (triton de V7 → résolution vers I). Même principe, plus grande échelle." },

  // Formes musicales
  { q: "Qu'est-ce que la forme ABA ?", opts: ["3 sections identiques", "Section A (principale) — section B contrastante — retour de A", "A répété deux fois puis B", "Une forme de 32 mesures"], a: 1, fb: "La forme ABA (lied) présente A (thème principal), B contrastant (nouvelle tonalité ou mode), puis le retour de A. La symétrie A–B–A crée équilibre et satisfaction : on part, on revient. Omniprésent dans les Nocturnes de Chopin et les arias d'opéra." },
  { q: "La forme AABA de 32 mesures est :", opts: ["4 sections identiques", "A (8 mes.) répété 2 fois, pont B (8 mes.) contrastant, retour de A (8 mes.)", "A répété 4 fois", "Une forme uniquement classique"], a: 1, fb: "AABA = 32 mesures : A (8) + A (8) + B pont (8) + A (8). Le pont B est souvent dans une tonalité voisine ou avec un rythme harmonique différent. C'est la forme standard des standards jazz américains des années 1930–60." },
  { q: "Dans la forme AABA, la section B est appelée :", opts: ["Coda", "Pont (bridge)", "Refrain", "Développement"], a: 1, fb: "La section B dans une forme AABA est le 'pont' (bridge). Il contraste avec A par la tonalité, le rythme harmonique ou la texture. Le pont crée la variété nécessaire avant le retour final de A — 'on revient à la maison'." },
  { q: "Autumn Leaves utilise quelle forme ?", opts: ["ABA", "AABA", "ABAB", "Blues 12 mesures"], a: 1, fb: "Autumn Leaves (Kosma, 1945) est en forme AABA de 32 mesures. C'est l'un des standards les plus joués pour enseigner la forme jazz — ses deux II–V–I successifs (majeur et mineur) dans la section A en font aussi un exemple de progression type." },
  { q: "Le blues sur 12 mesures est structuré autour de :", opts: ["I–V–I seulement", "I7 (4 mes.) – IV7 (2 mes.) – I7 (2 mes.) – II–V–I (4 mes.)", "16 mesures égales", "Deux sections de 6 mesures"], a: 1, fb: "Blues 12 mesures : I7 (4 mes.) | IV7 (2 mes.) | I7 (2 mes.) | turnaround (4 mes.). Structure de question/réponse/résolution à l'échelle de 12 mesures. Forme prévisible dont la stabilité libère l'improvisateur." },
  { q: "La forme sonate comprend :", opts: ["Un seul thème développé", "Exposition (thèmes A+B), Développement, Réexposition", "Introduction et Coda seulement", "4 sections de 8 mesures"], a: 1, fb: "Forme sonate : Exposition = thème A (tonique) + thème B (dominante/relatif) ; Développement = manipulation thématique dans des tonalités éloignées ; Réexposition = A et B en tonique. La forme la plus téléologique du classicisme." },
  { q: "Dans la forme sonate, le 'développement' se caractérise par :", opts: ["La répétition de l'exposition", "La manipulation thématique — fragmenter, moduler — dans des tonalités éloignées", "L'introduction de nouveaux thèmes", "La conclusion du morceau"], a: 1, fb: "Le développement est la section la plus instable. Les thèmes de l'exposition sont fragmentés, transformés, transposés dans des tonalités éloignées — c'est le 'voyage' entre l'exposition (départ) et la réexposition (retour). Beethoven excelle dans l'art du développement." },
  { q: "Pourquoi la forme crée-t-elle le sens musical ?", opts: ["Car elle détermine la durée", "Car elle organise le temps — sans forme, une succession d'accords n'est qu'une liste sans direction ni sens", "Car elle fixe le tempo", "Car elle indique l'instrumentation"], a: 1, fb: "La forme donne une direction au discours musical. Sans forme, une suite d'accords est 'hors sol' — on ne sait ni d'où l'on vient ni où l'on va. La forme crée l'attente (tension) et sa résolution (satisfaction) : c'est la rhétorique de la musique." },
  { q: "La forme couplet-refrain est :", opts: ["Identique à la forme sonate", "Alternance entre couplets (contenu narratif changeant) et refrain (mélodie récurrente identique)", "Trois sections identiques", "Une forme uniquement instrumentale"], a: 1, fb: "Couplet-refrain : les couplets racontent (texte et parfois mélodie variables) ; le refrain revient avec le même texte et la même mélodie. Forme dominante de la chanson populaire (pop, rock, folk). Elle allie variété (couplets) et récurrence mémorable (refrain)." },
  { q: "La forme rondo est :", opts: ["ABA uniquement", "Un thème A qui revient alternativement entre des épisodes contrastants : ABACADA...", "Une forme de 32 mesures jazz", "Deux sections de développement"], a: 1, fb: "Le rondo alterne un refrain (thème A) avec des épisodes contrastants (B, C, D...). Le thème A (souvent mémorable) revient comme ancrage entre des aventures musicales contrastantes. Très présent dans les finales de sonates classiques." },

  // Schoenberg et théorie
  { q: "Schoenberg a formalisé la notion de phrase musicale dans :", opts: ["Die Kunst der Fuge", "Fundamentals of Musical Composition (rédigé dans les années 1930–40)", "Le Clavecin bien tempéré", "Traité d'orchestration de Berlioz"], a: 1, fb: "Arnold Schoenberg a rédigé Fundamentals of Musical Composition dans les années 1930–40 à UCLA, publié posthumement en 1967. Ce traité pédagogique analyse systématiquement la phrase, le motif, la période et les grandes formes — référence fondamentale pour l'enseignement de la composition." },
  { q: "Schoenberg distingue deux types de marches musicales :", opts: ["Marche lente et marche rapide", "Marche tonale (diatonique) et marche réelle (transposition stricte, parfois chromatique)", "Marche ascendante et descendante", "Marche simple et double"], a: 1, fb: "Marche tonale : le motif s'adapte aux intervalles de la gamme diatonique. Marche réelle : transposition stricte du même intervalle exact (peut sortir de la gamme). Cette distinction est centrale dans l'analyse de Schoenberg — les deux types ont des effets expressifs très différents." },
  { q: "Le concept de 'liquidation' chez Schoenberg désigne :", opts: ["La suppression d'accords", "L'élimination progressive des caractéristiques distinctives du motif en fin de phrase pour signaler la cadence", "Un changement de tonalité", "La réduction du nombre de voix"], a: 1, fb: "La liquidation est le processus par lequel un motif perd progressivement ses traits distinctifs en fin de phrase. On en garde le rythme, puis juste le contour, puis presque rien — la phrase se dissout dans la cadence. Procédé rhétorique de 'conclusion' très sophistiqué." },
  { q: "Selon Schoenberg, la répétition dans la composition musicale sert à :", opts: ["Allonger un morceau sans effort", "Établir la cohérence — l'auditeur reconnaît ce qu'il a déjà entendu et peut suivre le discours musical", "Compenser le manque d'idées", "Satisfaire aux conventions du genre"], a: 1, fb: "Schoenberg insiste sur la répétition comme outil de cohérence (Verständlichkeit). Un motif répété (même transformé) est reconnaissable. La répétition crée le sentiment d'une idée développée plutôt qu'une succession d'idées disparates — c'est la 'compréhensibilité' musicale." },
  { q: "Schoenberg est paradoxalement aussi célèbre pour :", opts: ["Avoir inventé la tonalité", "Avoir développé le dodécaphonisme — composition avec les 12 demi-tons à égalité, sans tonalité centrale", "Avoir composé uniquement du jazz", "Avoir écrit des opéras baroques"], a: 1, fb: "Schoenberg est le théoricien de la phrase tonale ET le fondateur du dodécaphonisme (méthode des 12 sons, 1921). Paradoxe : son traité analyse la forme tonale, mais sa musique (Pierrot Lunaire, Suite op.25) abolit la tonalité. Il est le pont entre tradition et rupture." },

  // Applications pratiques
  { q: "Qu'est-ce qui distingue une progression 'hors sol' d'une vraie phrase musicale ?", opts: ["Le nombre d'accords", "La phrase a un motif directeur, une structure d'étapes et une cadence — la progression 'hors sol' n'a ni direction ni conclusion", "La tonalité", "Le tempo"], a: 1, fb: "Une progression 'hors sol' = accords enchaînés sans logique motivique ni cadence préméditée. Une phrase musicale = motif + développement en 4 étapes + cadence. La différence est celle entre une conversation (discours structuré) et une liste de mots (absence de discours)." },
  { q: "Comment reconnaît-on une cadence dans une phrase musicale ?", opts: ["Par un silence", "Par un repos sur V (demi-cadence) ou I (cadence parfaite) — moment de résolution de la tension harmonique", "Par un changement de tempo", "Par une note plus aiguë"], a: 1, fb: "La cadence est un moment de repos harmonique. Demi-cadence (V) : question suspendue. Cadence parfaite (I) : résolution complète. Cadence plagale (IV–I) : conclusion douce. Cadence rompue (V→VI) : résolution déceptive. Chaque type crée un effet de ponctuation différent." },
  { q: "Dans un standard jazz de forme AABA, le pont (B) sert à :", opts: ["Répéter A", "Créer un contraste harmonique et mélodique qui rend le retour de A d'autant plus satisfaisant", "Conclure le morceau", "Introduire le soliste uniquement"], a: 1, fb: "Le pont crée un contraste — souvent dans une tonalité voisine, avec un rythme harmonique ou une direction mélodique opposée à A. Ce contraste rend le retour final de A plus attendu et plus satisfaisant — 'on revient à la maison'. C'est la dialectique tension/résolution à l'échelle formelle." },
  { q: "La Sonate Pathétique de Beethoven est un exemple classique de la phrase de 8 mesures car :", opts: ["Elle dure 8 minutes", "Son premier thème illustre les 4 étapes : idée de base, répétition, accélération (liquidation), cadence", "Elle n'a que 8 mesures", "Schoenberg l'a analysée dans son traité"], a: 1, fb: "Le premier thème de l'Allegro de la Pathétique (op.13, 1798) illustre les 4 étapes : motif distinctif (mes. 1–2), répétition transformée (mes. 3–4), accélération avec liquidation (mes. 5–7), cadence (mes. 8). Exemple pédagogique parfait régulièrement cité dans les traités d'analyse." },
  { q: "Comment marche harmonique et marche mélodique sont-elles liées ?", opts: ["Elles sont toujours opposées", "La marche mélodique répète un motif à des hauteurs successives ; la marche harmonique soutient ces hauteurs par des accords progressant dans le même sens", "Elles sont toujours indépendantes", "La marche harmonique précède toujours la mélodie"], a: 1, fb: "Dans une marche, mélodie et harmonie avancent ensemble : mélodie Do–Mi–Sol, Ré–Fa–La, Mi–Sol–Si (marche mélodique ascendante) sur des accords I, II, III (marche harmonique ascendante). Les deux dimensions bougent en parallèle — c'est ce qui crée l'effet de progression soutenu." },
  { q: "Pourquoi le blues sur 12 mesures est-il considéré comme une forme musicale ?", opts: ["Car il dure toujours 12 secondes", "Car il a une structure répétable et prévisible (I7–IV7–I7–V7–I7) créant attentes et résolutions à chaque cycle", "Car il ne contient que 3 accords", "Car il vient du Delta du Mississippi"], a: 1, fb: "Le blues 12 mesures est une forme car sa structure est prévisible et partagée par musiciens et auditeurs. Cette prévisibilité est une ressource : l'improvisateur peut jouer 'sur' la forme (contre les attentes) ou 'avec' (en les confirmant). La forme = cadre du discours musical." },
  { q: "Quelle est la longueur typique d'une phrase musicale dans le répertoire classique et jazz ?", opts: ["4 mesures", "8 mesures", "12 mesures", "16 mesures"], a: 1, fb: "8 mesures est la longueur standard de la phrase. Cette convention s'est établie au XVIIIe siècle et est passée dans le jazz (sections A et B de la forme AABA font chacune 8 mesures). La période (antécédent + conséquent) fait donc typiquement 16 mesures (8+8)." },
  { q: "Qu'est-ce qu'un 'thème' par rapport à un 'motif' ?", opts: ["Un thème est plus court qu'un motif", "Le motif est le plus petit élément ; le thème est une idée plus développée (souvent une phrase entière) construite à partir d'un ou plusieurs motifs", "Un thème est harmonique, un motif est mélodique", "Ce sont des synonymes exacts"], a: 1, fb: "Motif = cellule minimale (4 notes). Thème = idée musicale développée (souvent 8–16 mesures) construite à partir d'un ou plusieurs motifs. Le thème est mémorable et 'jouable' ; le motif est le 'germe' générateur. Beethoven tire de grands thèmes d'un seul motif de 4 notes." },
  { q: "Dans la forme sonate classique, l'exposition présente généralement :", opts: ["Un seul thème", "Deux thèmes contrastants — thème A (tonique) et thème B (dominante ou relatif mineur)", "Quatre thèmes", "Le développement uniquement"], a: 1, fb: "L'exposition présente deux thèmes : A (tonique, souvent énergique) et B (dominante si majeur, relatif si mineur — souvent plus lyrique). Ce contraste A/B crée la 'tension dramatique' que le développement et la réexposition vont explorer et résoudre." },
  { q: "Un 'motif récurrent' dans une grande forme (leitmotiv, idée fixe) sert à :", opts: ["Répéter un passage de façon mécanique", "Créer une unité à grande échelle — le motif réapparaît à des moments clés pour tisser la cohérence de toute l'œuvre", "Faciliter la mémorisation du musicien", "Indiquer une modulation"], a: 1, fb: "Le motif récurrent crée la cohérence à grande échelle. Wagner utilise des Leitmotive associés à des personnages qui reviennent tout au long d'un opéra. Berlioz invente l'idée fixe (Symphonie Fantastique). C'est la logique de la forme ABA étendue à l'échelle d'une œuvre entière." },
  { q: "La forme ABAC est notamment utilisée dans :", opts: ["Le blues", "All The Things You Are, My Romance — standards avec deux deuxièmes voltes différentes (B puis C)", "La symphonie classique", "Le rondo"], a: 1, fb: "ABAC : A revient deux fois mais se termine différemment la seconde fois (C au lieu de B). All The Things You Are (Kern, 1939) en est l'exemple le plus célèbre. Chaque retour de A est légèrement différent dans sa conclusion — légère surprise malgré la récurrence." },
  { q: "Pourquoi comprendre la forme est-il utile pour un improvisateur jazz ?", opts: ["Pour respecter les conventions", "Pour savoir où l'on est dans la grille — début ou fin de A, pont B, retour final — et adapter son jeu en conséquence", "Pour lire la partition", "Pour jouer plus de notes"], a: 1, fb: "Un improvisateur qui connaît la forme joue 'avec' la structure : plus de tension au pont (B), résolution plus marquée au retour de A, climax placé au bon moment. Ignorer la forme revient à improviser 'dans le vide' — techniquement correct mais musicalement inexpressif." },
];

// English translations — add when available; until then falls back to fr


const questionsEn: Question[] = [{ q: "What is a musical motif?", opts: ["A 4-note chord", "The smallest distinctive musical element — the guiding thread of a phrase's discourse", "A complete scale", "A dominant chord"], a: 1, fb: "The motif is the smallest recognizable and structuring musical element. It contains the rhythmic and/or melodic identity that will be repeated and transformed. Beethoven builds his entire 5th Symphony from a motif of just 4 notes (G–G–G–Eb)." },
{ q: "The motif from Beethoven's 5th Symphony (G–G–G–Eb) illustrates that:", opts: ["A motif must be long to be expressive", "An extremely short motif can generate a complete musical discourse through repetition and transformation", "The 5th uses exclusively a minor mode", "This motif comes from a folk song"], a: 1, fb: "G–G–G–Eb: 4 notes, 3 repeated + a falling third. This motif is the seed of the entire 5th Symphony (1808). Beethoven fragments it, transposes it, augments it — demonstrating that a minimal motif can construct twenty minutes of music." },
{ q: "What is the difference between 'support music' and 'discourse music'?", opts: ["Support music is longer", "Support music accompanies an external action; discourse music develops its own musical ideas autonomously", "Discourse music is shorter", "There is no difference"], a: 1, fb: "Support music (film, ballet) serves an external action — its structure can be fragmented according to the narrative. Discourse music (sonata, fugue, jazz standard) develops its own ideas in a logical and autonomous way, independently of any extra-musical context." },
{ q: "The guiding thread of a musical phrase is:", opts: ["The key", "The motif — repeated and transformed to give coherence to the phrase", "The tempo", "The accompaniment"], a: 1, fb: "The motif is the guiding thread. Its repetition (strict or transformed) creates coherence. The listener recognizes the motif even when transformed — this is what gives the impression of a sustained musical discourse rather than a succession of disparate ideas." },

{ q: "How many stages does a typical 8-measure musical phrase have?", opts: ["2", "3", "4", "8"], a: 2, fb: "The 8-measure phrase follows 4 stages: (1) basic idea, (2) repetition, (3) acceleration/fragmentation, (4) cadence. This pattern is present in Beethoven, Mozart, Haydn, and in most standard jazz forms." },
{ q: "What is the first stage of a musical phrase?", opts: ["The cadence", "The basic idea — presentation of the main motif", "The repetition", "The liquidation"], a: 1, fb: "The basic idea is the statement of the phrase's 'subject': presentation of the motif or motivic cell. The 3 following stages (repetition, acceleration, cadence) flow from this initial idea." },
{ q: "What is the 'liquidation' of a phrase (Schoenberg's term)?", opts: ["Repeating the motif more slowly", "Accelerating the harmonic rhythm at the end of a phrase — harmonies change faster to signal the imminent cadence", "Reducing the number of instruments", "Playing more softly"], a: 1, fb: "Liquidation refers to the acceleration of harmonic rhythm at the end of a phrase. Harmonies that changed every 2 measures now change every measure, then on every beat — a rhetorical signal that the cadence is approaching: 'the conclusion is coming'." },
{ q: "In the 3rd stage of a Beethoven phrase, the acceleration manifests through:", opts: ["A faster tempo", "Fragmented motifs and a denser harmonic rhythm, creating tension before the cadence", "A change of instrument", "A lower melody"], a: 1, fb: "The acceleration of the 3rd stage = fragmentation of the motif and densification of harmonic rhythm. Beethoven repeats increasingly short motivic fragments, the chords change faster and faster — tension that 'calls for' the final cadence." },

{ q: "What is 'strict repetition' of a motif?", opts: ["Repeating in another key", "Repeating the motif identically — same pitches, same rhythm", "Repeating with ornaments", "Repeating only at the lower octave"], a: 1, fb: "Strict repetition reproduces the motif exactly. The most direct technique: the listener immediately recognizes the motif. It can seem mechanical; that is why it is often combined with other transformation techniques." },
{ q: "'Melodic transformation' of a motif consists of:", opts: ["Changing its rhythm", "Transposing the motif to another pitch while keeping the same rhythmic contour", "Inverting the intervals", "Playing the motif backwards"], a: 1, fb: "Melodic transformation transposes the motif — the rhythmic contour remains identical, the pitches change. C–E–G becomes D–F–A (a whole step higher). The rhythmic identity maintains coherence; the new pitch brings variety." },
{ q: "A musical 'sequence' (or march) is:", opts: ["A military march rhythm", "A motif repeated at successive scale degrees or by chromatic transposition", "A passing chord", "A 16-measure form"], a: 1, fb: "A sequence repeats a motif at successive pitches. Tonal sequence: stays within the diatonic scale. Real sequence (chromatic): strictly transposes the same interval (may leave the scale). Ex. C–E–G, D–F–A, E–G–B (ascending tonal sequence)." },
{ q: "The difference between a 'tonal sequence' and a 'real sequence' is:", opts: ["The tempo", "The tonal sequence stays diatonic (intervals slightly adjusted); the real sequence strictly transposes the same interval, creating chromaticisms", "The real sequence is longer", "There is no difference"], a: 1, fb: "A key distinction from Schoenberg: tonal sequence = the motif adapts to the scale's intervals (the interval may change slightly); real sequence = strict transposition of the exact same interval (may introduce notes foreign to the scale)." },
{ q: "A 'complementary' motif is:", opts: ["A motif that imitates the main one in unison", "A second motif that responds to the first, completing the rhythmic or melodic space of the phrase", "An inverted motif", "A motif played simultaneously"], a: 1, fb: "The complementary motif responds to the main motif — often in the following measures. Ex. Motif A (measures 1–2) + Motif B (measures 3–4). Together, A and B form the complete phrase; each is incomplete without the other." },
{ q: "'Melodic-harmonic transformation' consists of:", opts: ["Changing the rhythm and melody", "Keeping the melodic contour of the motif but changing the chords beneath it, altering the harmonic color", "Inverting the melody and the chords", "Transposing into 12 keys"], a: 1, fb: "Melodic-harmonic transformation preserves the recognizable melodic contour but changes the chords beneath. The melody C–E–G will sound different over I (Cmaj7) than over VI (Am7). The melody creates coherence; the harmony renews the expression." },

{ q: "What is a musical period?", opts: ["A 4-measure phrase", "A structure in two phrases: antecedent (weak cadence) + consequent (strong cadence)", "A group of 3 phrases", "A 32-measure section"], a: 1, fb: "The period is binary: the antecedent (phrase 1) ends on a weak cadence (often V — half cadence), creating a question. The consequent (phrase 2) ends on a strong cadence (I — perfect cadence), providing the answer. Typical length: 16 measures (8+8)." },
{ q: "The antecedent of a period ends on:", opts: ["The tonic (I) — perfect cadence", "The dominant (V) — half cadence, effect of a suspended question", "The subdominant (IV)", "The mediant (III)"], a: 1, fb: "The antecedent ends on V (half cadence) — the ear awaits a conclusion. This is the 'question'. The consequent responds by ending on I. This question/answer pattern is the fundamental rhetorical structure of tonal music." },
{ q: "The consequent of a period ends on:", opts: ["The dominant (V)", "The tonic (I) — perfect cadence, conclusion", "The subdominant (IV)", "A seventh chord"], a: 1, fb: "The consequent ends on I (perfect cadence). After the 'question' of the antecedent (which ends on V), the consequent provides the conclusive 'answer' by anchoring on the tonic. This is the most natural musical rhetoric." },
{ q: "The main difference between a phrase and a period is:", opts: ["Length only", "The phrase = an autonomous unit (8 measures) with its own cadence; the period = two phrases (antecedent + consequent, 16 measures) with a weak then strong cadence", "The number of motifs", "The key"], a: 1, fb: "The phrase is an autonomous unit (typically 8 measures) with its own cadence. The period is a structure of two phrases: antecedent (V cadence — question) + consequent (I cadence — answer). The period therefore typically spans 16 measures." },
{ q: "Antecedent and consequent often share:", opts: ["Exactly the same notes", "The same opening thematic material — linked by the same initial motif, but concluded differently", "The same tempo", "Absolutely the same duration"], a: 1, fb: "Antecedent and consequent often begin with the same motif — this is what unites them into a coherent period. But their endings differ: V cadence (antecedent) vs. I cadence (consequent). Same beginning, contrasting conclusions: question/answer." },
{ q: "The 'question/answer' effect in a period is created by:", opts: ["Two different motifs", "The weak cadence of the antecedent (V) which creates expectation, resolved by the strong cadence of the consequent (I)", "A change of tempo", "An increase in volume"], a: 1, fb: "V (half cadence) = suspended question. I (perfect cadence) = conclusive answer. This question/answer pattern at the scale of the period reflects the same logic as tension/resolution at the scale of the chord (tritone of V7 → resolution to I). Same principle, larger scale." },

{ q: "What is ABA form?", opts: ["3 identical sections", "Section A (main) — contrasting section B — return of A", "A repeated twice then B", "A 32-measure form"], a: 1, fb: "ABA form (lied) presents A (main theme), contrasting B (new key or mode), then the return of A. The A–B–A symmetry creates balance and satisfaction: we depart, we return. Omnipresent in Chopin's Nocturnes and opera arias." },
{ q: "The 32-measure AABA form is:", opts: ["4 identical sections", "A (8 measures) repeated twice, contrasting bridge B (8 measures), return of A (8 measures)", "A repeated 4 times", "An exclusively classical form"], a: 1, fb: "AABA = 32 measures: A (8) + A (8) + B bridge (8) + A (8). The bridge B is often in a related key or with different harmonic rhythm. This is the standard form of American jazz standards from the 1930s–60s." },
{ q: "In AABA form, section B is called:", opts: ["Coda", "Bridge", "Chorus", "Development"], a: 1, fb: "Section B in an AABA form is the 'bridge'. It contrasts with A through key, harmonic rhythm, or texture. The bridge creates the necessary variety before the final return of A — 'we return home'." },
{ q: "Autumn Leaves uses which form?", opts: ["ABA", "AABA", "ABAB", "12-bar blues"], a: 1, fb: "Autumn Leaves (Kosma, 1945) is in 32-measure AABA form. It is one of the most played standards for teaching jazz form — its two successive II–V–I progressions (major and minor) in the A section also make it a classic example of a typical progression." },
{ q: "The 12-bar blues is structured around:", opts: ["I–V–I only", "I7 (4 measures) – IV7 (2 measures) – I7 (2 measures) – II–V–I (4 measures)", "16 equal measures", "Two 6-measure sections"], a: 1, fb: "12-bar blues: I7 (4 measures) | IV7 (2 measures) | I7 (2 measures) | turnaround (4 measures). A question/answer/resolution structure on the scale of 12 measures. A predictable form whose stability liberates the improviser." },
{ q: "Sonata form comprises:", opts: ["A single developed theme", "Exposition (themes A+B), Development, Recapitulation", "Introduction and Coda only", "4 sections of 8 measures"], a: 1, fb: "Sonata form: Exposition = theme A (tonic) + theme B (dominant/relative); Development = thematic manipulation in distant keys; Recapitulation = A and B in the tonic. The most teleological form of classicism." },
{ q: "In sonata form, the 'development' is characterized by:", opts: ["The repetition of the exposition", "Thematic manipulation — fragmenting, modulating — in distant keys", "The introduction of new themes", "The conclusion of the piece"], a: 1, fb: "The development is the most unstable section. The themes from the exposition are fragmented, transformed, transposed into distant keys — it is the 'journey' between the exposition (departure) and the recapitulation (return). Beethoven excels in the art of development." },
{ q: "Why does form create musical meaning?", opts: ["Because it determines duration", "Because it organizes time — without form, a succession of chords is merely a list with no direction or meaning", "Because it sets the tempo", "Because it indicates the instrumentation"], a: 1, fb: "Form gives direction to musical discourse. Without form, a sequence of chords is 'groundless' — one knows neither where one has come from nor where one is going. Form creates expectation (tension) and its resolution (satisfaction): this is the rhetoric of music." },
{ q: "Verse-chorus form is:", opts: ["Identical to sonata form", "An alternation between verses (changing narrative content) and a chorus (identical recurring melody)", "Three identical sections", "An exclusively instrumental form"], a: 1, fb: "Verse-chorus: the verses narrate (variable text and sometimes melody); the chorus returns with the same text and melody. The dominant form of popular song (pop, rock, folk). It combines variety (verses) with memorable recurrence (chorus)." },
{ q: "Rondo form is:", opts: ["ABA only", "A theme A that returns alternately between contrasting episodes: ABACADA...", "A 32-measure jazz form", "Two development sections"], a: 1, fb: "The rondo alternates a refrain (theme A) with contrasting episodes (B, C, D...). Theme A (often memorable) returns as an anchor between contrasting musical adventures. Very common in the finales of classical sonatas." },

{ q: "Schoenberg formalized the notion of the musical phrase in:", opts: ["Die Kunst der Fuge", "Fundamentals of Musical Composition (written in the 1930s–40s)", "The Well-Tempered Clavier", "Berlioz's Treatise on Instrumentation"], a: 1, fb: "Arnold Schoenberg wrote Fundamentals of Musical Composition in the 1930s–40s at UCLA, published posthumously in 1967. This pedagogical treatise systematically analyzes the phrase, motif, period, and large forms — a fundamental reference for the teaching of composition." },
{ q: "Schoenberg distinguishes two types of musical sequences:", opts: ["Slow sequence and fast sequence", "Tonal sequence (diatonic) and real sequence (strict transposition, sometimes chromatic)", "Ascending and descending sequence", "Simple and double sequence"], a: 1, fb: "Tonal sequence: the motif adapts to the intervals of the diatonic scale. Real sequence: strict transposition of the exact same interval (may leave the scale). This distinction is central in Schoenberg's analysis — the two types have very different expressive effects." },
{ q: "The concept of 'liquidation' in Schoenberg refers to:", opts: ["The removal of chords", "The progressive elimination of the motif's distinctive characteristics at the end of a phrase to signal the cadence", "A change of key", "The reduction of the number of voices"], a: 1, fb: "Liquidation is the process by which a motif progressively loses its distinctive traits at the end of a phrase. The rhythm is kept, then just the contour, then almost nothing — the phrase dissolves into the cadence. A very sophisticated rhetorical device for 'conclusion'." },
{ q: "According to Schoenberg, repetition in musical composition serves to:", opts: ["Lengthen a piece without effort", "Establish coherence — the listener recognizes what they have already heard and can follow the musical discourse", "Compensate for a lack of ideas", "Satisfy the conventions of the genre"], a: 1, fb: "Schoenberg emphasizes repetition as a tool of coherence (Verständlichkeit). A repeated motif (even transformed) is recognizable. Repetition creates the sense of a developed idea rather than a succession of disparate ideas — this is musical 'comprehensibility'." },
{ q: "Schoenberg is paradoxically also famous for:", opts: ["Having invented tonality", "Having developed twelve-tone serialism — composition with all 12 semitones as equals, without a central key", "Having composed exclusively jazz", "Having written Baroque operas"], a: 1, fb: "Schoenberg is both the theorist of the tonal phrase AND the founder of twelve-tone serialism (twelve-tone method, 1921). Paradox: his treatise analyzes tonal form, but his music (Pierrot Lunaire, Suite op.25) abolishes tonality. He is the bridge between tradition and rupture." },

{ q: "What distinguishes a 'groundless' progression from a true musical phrase?", opts: ["The number of chords", "The phrase has a guiding motif, a staged structure, and a cadence — the 'groundless' progression has neither direction nor conclusion", "The key", "The tempo"], a: 1, fb: "A 'groundless' progression = chords chained without motivic logic or premeditated cadence. A musical phrase = motif + development in 4 stages + cadence. The difference is that between a conversation (structured discourse) and a list of words (absence of discourse)." },
{ q: "How does one recognize a cadence in a musical phrase?", opts: ["By a silence", "By a rest on V (half cadence) or I (perfect cadence) — a moment of resolution of harmonic tension", "By a change of tempo", "By a higher note"], a: 1, fb: "The cadence is a moment of harmonic rest. Half cadence (V): suspended question. Perfect cadence (I): complete resolution. Plagal cadence (IV–I): gentle conclusion. Deceptive cadence (V→VI): deceptive resolution. Each type creates a different punctuation effect." },
{ q: "In a jazz standard in AABA form, the bridge (B) serves to:", opts: ["Repeat A", "Create harmonic and melodic contrast that makes the return of A all the more satisfying", "Conclude the piece", "Introduce the soloist only"], a: 1, fb: "The bridge creates contrast — often in a related key, with harmonic rhythm or melodic direction opposed to A. This contrast makes the final return of A more anticipated and more satisfying — 'we return home'. This is the tension/resolution dialectic at the formal scale." },
{ q: "Beethoven's Pathétique Sonata is a classic example of the 8-measure phrase because:", opts: ["It lasts 8 minutes", "Its first theme illustrates the 4 stages: basic idea, repetition, acceleration (liquidation), cadence", "It has only 8 measures", "Schoenberg analyzed it in his treatise"], a: 1, fb: "The first theme of the Allegro of the Pathétique (op.13, 1798) illustrates the 4 stages: distinctive motif (measures 1–2), transformed repetition (measures 3–4), acceleration with liquidation (measures 5–7), cadence (measure 8). A perfect pedagogical example regularly cited in analysis treatises." },
{ q: "How are harmonic sequence and melodic sequence related?", opts: ["They are always opposed", "The melodic sequence repeats a motif at successive pitches; the harmonic sequence supports these pitches with chords progressing in the same direction", "They are always independent", "The harmonic sequence always precedes the melody"], a: 1, fb: "In a sequence, melody and harmony move together: melody C–E–G, D–F–A, E–G–B (ascending melodic sequence) over chords I, II, III (ascending harmonic sequence). Both dimensions move in parallel — this is what creates the sustained sense of progression." },
{ q: "Why is the 12-bar blues considered a musical form?", opts: ["Because it always lasts 12 seconds", "Because it has a repeatable and predictable structure (I7–IV7–I7–V7–I7) creating expectations and resolutions at each cycle", "Because it contains only 3 chords", "Because it comes from the Mississippi Delta"], a: 1, fb: "The 12-bar blues is a form because its structure is predictable and shared by musicians and listeners alike. This predictability is a resource: the improviser can play 'against' the form (against expectations) or 'with' it (confirming them). Form = the framework of musical discourse." },
{ q: "What is the typical length of a musical phrase in the classical and jazz repertoire?", opts: ["4 measures", "8 measures", "12 measures", "16 measures"], a: 1, fb: "8 measures is the standard phrase length. This convention was established in the 18th century and carried over into jazz (the A and B sections of AABA form each span 8 measures). The period (antecedent + consequent) therefore typically spans 16 measures (8+8)." },
{ q: "What is a 'theme' compared to a 'motif'?", opts: ["A theme is shorter than a motif", "The motif is the smallest element; the theme is a more developed idea (often a complete phrase) built from one or more motifs", "A theme is harmonic, a motif is melodic", "They are exact synonyms"], a: 1, fb: "Motif = minimal cell (4 notes). Theme = developed musical idea (often 8–16 measures) built from one or more motifs. The theme is memorable and 'singable'; the motif is the generative 'seed'. Beethoven draws great themes from a single 4-note motif." },
{ q: "In classical sonata form, the exposition generally presents:", opts: ["A single theme", "Two contrasting themes — theme A (tonic) and theme B (dominant or relative minor)", "Four themes", "The development only"], a: 1, fb: "The exposition presents two themes: A (tonic, often energetic) and B (dominant if major, relative if minor — often more lyrical). This A/B contrast creates the 'dramatic tension' that the development and recapitulation will explore and resolve." },
{ q: "A 'recurring motif' in a large form (leitmotiv, idée fixe) serves to:", opts: ["Repeat a passage mechanically", "Create large-scale unity — the motif reappears at key moments to weave coherence throughout the entire work", "Help the musician memorize", "Indicate a modulation"], a: 1, fb: "The recurring motif creates coherence on a large scale. Wagner uses Leitmotive associated with characters that recur throughout an opera. Berlioz invents the idée fixe (Symphonie Fantastique). It is the logic of ABA form extended to the scale of an entire work." },
{ q: "ABAC form is notably used in:", opts: ["The blues", "All The Things You Are, My Romance — standards with two different second endings (B then C)", "The classical symphony", "The rondo"], a: 1, fb: "ABAC: A returns twice but ends differently the second time (C instead of B). All The Things You Are (Kern, 1939) is the most celebrated example. Each return of A differs slightly in its conclusion — a gentle surprise despite the recurrence." },
{ q: "Why is understanding form useful for a jazz improviser?", opts: ["To follow conventions", "To know where one is in the chart — beginning or end of A, bridge B, final return — and adapt one's playing accordingly", "To read the score", "To play more notes"], a: 1, fb: "An improviser who knows the form plays 'with' the structure: more tension at the bridge (B), more marked resolution at the return of A, climax placed at the right moment. Ignoring form means improvising 'in a vacuum' — technically correct but musically inexpressive." },
];

const questionsEs: Question[] = [{ q: "¿Qué es un motivo musical?", opts: ["Un acorde de 4 sonidos", "El elemento musical distintivo más pequeño — hilo conductor del discurso de una frase", "Una escala completa", "Un acorde de dominante"], a: 1, fb: "El motivo es el elemento musical reconocible y estructurante más pequeño. Contiene la identidad rítmica y/o melódica que será repetida y transformada. Beethoven construye toda su 5.ª Sinfonía a partir de un motivo de tan solo 4 notas (G–G–G–Eb)." },
{ q: "El motivo de la 5.ª Sinfonía de Beethoven (G–G–G–Eb) ilustra que:", opts: ["Un motivo debe ser largo para ser expresivo", "Un motivo extremadamente corto puede generar un discurso musical completo mediante repetición y transformación", "La 5.ª utiliza un modo menor exclusivamente", "Este motivo proviene de una canción popular"], a: 1, fb: "G–G–G–Eb: 4 notas, 3 repetidas + una caída de tercera. Este motivo es el germen de toda la 5.ª Sinfonía (1808). Beethoven lo fragmenta, lo transpone, lo aumenta — demostrando que un motivo mínimo puede construir veinte minutos de música." },
{ q: "¿Cuál es la diferencia entre 'música de soporte' y 'música de discurso'?", opts: ["La música de soporte es más larga", "La música de soporte acompaña una acción exterior; la música de discurso desarrolla sus propias ideas musicales de forma autónoma", "La música de discurso es más corta", "No hay ninguna diferencia"], a: 1, fb: "La música de soporte (cine, ballet) sirve a una acción exterior — su estructura puede estar fragmentada según la narración. La música de discurso (sonata, fuga, estándar de jazz) desarrolla sus propias ideas de forma lógica y autónoma, independientemente de todo contexto extra-musical." },
{ q: "El hilo conductor de una frase musical es:", opts: ["La tonalidad", "El motivo — repetido y transformado para dar coherencia a la frase", "El tempo", "El acompañamiento"], a: 1, fb: "El motivo es el hilo conductor. Su repetición (estricta o transformada) crea la coherencia. El oyente reconoce el motivo incluso transformado — es lo que da la impresión de un discurso musical continuo en lugar de una sucesión de ideas dispares." },
{ q: "¿Cuántas etapas tiene una frase musical típica de 8 compases?", opts: ["2", "3", "4", "8"], a: 2, fb: "La frase de 8 compases sigue 4 etapas: (1) idea de base, (2) repetición, (3) aceleración/fragmentación, (4) cadencia. Este esquema está presente en Beethoven, Mozart, Haydn y en la mayoría de las formas del jazz estándar." },
{ q: "¿Cuál es la primera etapa de una frase musical?", opts: ["La cadencia", "La idea de base — presentación del motivo principal", "La repetición", "La liquidación"], a: 1, fb: "La idea de base es el enunciado del 'tema' de la frase: presentación del motivo o de la célula motivica. Las 3 etapas siguientes (repetición, aceleración, cadencia) se derivan de esta idea inicial." },
{ q: "¿Qué es la 'liquidación' de una frase (término de Schoenberg)?", opts: ["Repetir el motivo más lentamente", "Acelerar el ritmo armónico al final de la frase — las armonías cambian más rápido para señalar la cadencia inminente", "Reducir el número de instrumentos", "Tocar más suave"], a: 1, fb: "La liquidación designa la aceleración del ritmo armónico al final de la frase. Las armonías que cambiaban cada 2 compases ahora cambian cada compás, luego en cada tiempo — señal retórica de que la cadencia se aproxima: 'la conclusión llega'." },
{ q: "En la 3.ª etapa de una frase de Beethoven, la aceleración se manifiesta por:", opts: ["Un tempo más rápido", "Motivos fragmentados y un ritmo armónico más denso, creando tensión antes de la cadencia", "Un cambio de instrumento", "Una melodía más grave"], a: 1, fb: "La aceleración de la 3.ª etapa = fragmentación del motivo y densificación del ritmo armónico. Beethoven repite fragmentos de motivo cada vez más cortos, los acordes cambian cada vez más rápido — tensión que 'llama' a la cadencia final." },
{ q: "¿Qué es la 'repetición estricta' de un motivo?", opts: ["Repetir en otra tonalidad", "Repetir el motivo de forma idéntica — mismas alturas, mismo ritmo", "Repetir con ornamentos", "Repetir únicamente en la octava inferior"], a: 1, fb: "La repetición estricta reproduce el motivo exactamente. Técnica más directa: el oyente reconoce inmediatamente el motivo. Puede parecer mecánica; por eso suele combinarse con otras técnicas de transformación." },
{ q: "La 'transformación melódica' de un motivo consiste en:", opts: ["Cambiar su ritmo", "Transponer el motivo a otra altura conservando el mismo contorno rítmico", "Invertir los intervalos", "Tocar el motivo al revés"], a: 1, fb: "La transformación melódica transpone el motivo — el contorno rítmico permanece idéntico, las alturas cambian. C–E–G se convierte en D–F–A (un tono más alto). La identidad rítmica mantiene la coherencia; la nueva altura aporta la variedad." },
{ q: "Una 'marcha' (o secuencia) musical es:", opts: ["Un ritmo de marcha militar", "Un motivo repetido en grados sucesivos de la escala o por transposición cromática", "Un acorde de paso", "Una forma de 16 compases"], a: 1, fb: "La marcha (secuencia) repite un motivo a alturas sucesivas. Marcha tonal: permanece en la escala diatónica. Marcha real (cromática): transpone estrictamente el mismo intervalo (puede salir de la escala). Ej. C–E–G, D–F–A, E–G–B (marcha tonal ascendente)." },
{ q: "La diferencia entre 'marcha tonal' y 'marcha real' es:", opts: ["El tempo", "La marcha tonal permanece diatónica (intervalos ligeramente ajustados); la marcha real transpone estrictamente el mismo intervalo, creando cromatismos", "La marcha real es más larga", "No hay ninguna diferencia"], a: 1, fb: "Distinción clave de Schoenberg: marcha tonal = el motivo se adapta a los intervalos de la escala (puede cambiar ligeramente de intervalo); marcha real = transposición estricta del mismo intervalo (puede introducir notas ajenas a la escala)." },
{ q: "Un motivo 'complementario' es:", opts: ["Un motivo que imita al principal al unísono", "Un segundo motivo que responde al primero, completando el espacio rítmico o melódico de la frase", "Un motivo invertido", "Un motivo tocado simultáneamente"], a: 1, fb: "El motivo complementario responde al motivo principal — a menudo en los compases siguientes. Ej. Motivo A (compases 1–2) + Motivo B (compases 3–4). Juntos, A y B forman la frase completa; cada uno es incompleto sin el otro." },
{ q: "La 'transformación melódico-armónica' consiste en:", opts: ["Cambiar el ritmo y la melodía", "Conservar el contorno melódico del motivo pero cambiar los acordes por debajo, modificando el color armónico", "Invertir la melodía y los acordes", "Transponer en 12 tonalidades"], a: 1, fb: "La transformación melódico-armónica conserva el contorno melódico reconocible pero cambia los acordes por debajo. La melodía C–E–G sonará diferente sobre I (Cmaj7) que sobre VI (Am7). La melodía crea la coherencia; la armonía renueva la expresión." },
{ q: "¿Qué es un período musical?", opts: ["Una frase de 4 compases", "Una estructura en dos frases: antecedente (cadencia débil) + consecuente (cadencia fuerte)", "Un grupo de 3 frases", "Una sección de 32 compases"], a: 1, fb: "El período es binario: el antecedente (frase 1) termina en una cadencia débil (a menudo V — semicadencia), creando una pregunta. El consecuente (frase 2) termina en una cadencia fuerte (I — cadencia perfecta), aportando la respuesta. Longitud típica: 16 compases (8+8)." },
{ q: "El antecedente de un período termina en:", opts: ["La tónica (I) — cadencia perfecta", "La dominante (V) — semicadencia, efecto de pregunta suspendida", "La subdominante (IV)", "La mediante (III)"], a: 1, fb: "El antecedente termina en V (semicadencia) — el oído espera una conclusión. Es la 'pregunta'. El consecuente responde terminando en I. Este esquema pregunta/respuesta es la estructura retórica fundamental de la música tonal." },
{ q: "El consecuente de un período termina en:", opts: ["La dominante (V)", "La tónica (I) — cadencia perfecta, conclusión", "La subdominante (IV)", "Un acorde de séptima"], a: 1, fb: "El consecuente termina en I (cadencia perfecta). Tras la 'pregunta' del antecedente (que termina en V), el consecuente aporta la 'respuesta' conclusiva al anclarse en la tónica. Es la retórica musical más natural." },
{ q: "La diferencia principal entre una frase y un período es:", opts: ["Solo la longitud", "La frase = una unidad autónoma (8 comp.) con su cadencia; el período = dos frases (antecedente + consecuente, 16 comp.) con cadencia débil luego fuerte", "El número de motivos", "La tonalidad"], a: 1, fb: "La frase es una unidad autónoma (típicamente 8 compases) con su propia cadencia. El período es una estructura de dos frases: antecedente (cadencia V — pregunta) + consecuente (cadencia I — respuesta). El período tiene por tanto típicamente 16 compases." },
{ q: "El antecedente y el consecuente comparten a menudo:", opts: ["Exactamente las mismas notas", "El mismo material temático inicial — unidos por un mismo motivo inicial, pero concluidos de forma diferente", "El mismo tempo", "La misma duración de forma absoluta"], a: 1, fb: "El antecedente y el consecuente comienzan a menudo con el mismo motivo — es lo que los une en un período coherente. Pero sus finales difieren: cadencia V (antecedente) vs. cadencia I (consecuente). Mismo comienzo, conclusiones contrastantes: pregunta/respuesta." },
{ q: "El efecto de 'pregunta/respuesta' en un período es creado por:", opts: ["Dos motivos diferentes", "La cadencia débil del antecedente (V) que crea la expectativa, resuelta por la cadencia fuerte del consecuente (I)", "El cambio de tempo", "El aumento del volumen"], a: 1, fb: "V (semicadencia) = pregunta suspendida. I (cadencia perfecta) = respuesta conclusiva. Este esquema pregunta/respuesta a escala del período refleja la misma lógica que la tensión/resolución a escala del acorde (tritono de V7 → resolución hacia I). Mismo principio, mayor escala." },
{ q: "¿Qué es la forma ABA?", opts: ["3 secciones idénticas", "Sección A (principal) — sección B contrastante — retorno de A", "A repetido dos veces luego B", "Una forma de 32 compases"], a: 1, fb: "La forma ABA (lied) presenta A (tema principal), B contrastante (nueva tonalidad o modo), luego el retorno de A. La simetría A–B–A crea equilibrio y satisfacción: se parte, se regresa. Omnipresente en los Nocturnos de Chopin y las arias de ópera." },
{ q: "La forma AABA de 32 compases es:", opts: ["4 secciones idénticas", "A (8 comp.) repetido 2 veces, puente B (8 comp.) contrastante, retorno de A (8 comp.)", "A repetido 4 veces", "Una forma únicamente clásica"], a: 1, fb: "AABA = 32 compases: A (8) + A (8) + B puente (8) + A (8). El puente B está a menudo en una tonalidad vecina o con un ritmo armónico diferente. Es la forma estándar de los estándares de jazz americanos de los años 1930–60." },
{ q: "En la forma AABA, la sección B se llama:", opts: ["Coda", "Puente (bridge)", "Estribillo", "Desarrollo"], a: 1, fb: "La sección B en una forma AABA es el 'puente' (bridge). Contrasta con A por la tonalidad, el ritmo armónico o la textura. El puente crea la variedad necesaria antes del retorno final de A — 'se vuelve a casa'." },
{ q: "Autumn Leaves utiliza qué forma?", opts: ["ABA", "AABA", "ABAB", "Blues de 12 compases"], a: 1, fb: "Autumn Leaves (Kosma, 1945) está en forma AABA de 32 compases. Es uno de los estándares más tocados para enseñar la forma jazz — sus dos II–V–I sucesivos (mayor y menor) en la sección A lo convierten también en un ejemplo de progresión típica." },
{ q: "El blues de 12 compases está estructurado alrededor de:", opts: ["I–V–I solamente", "I7 (4 comp.) – IV7 (2 comp.) – I7 (2 comp.) – II–V–I (4 comp.)", "16 compases iguales", "Dos secciones de 6 compases"], a: 1, fb: "Blues de 12 compases: I7 (4 comp.) | IV7 (2 comp.) | I7 (2 comp.) | turnaround (4 comp.). Estructura de pregunta/respuesta/resolución a escala de 12 compases. Forma previsible cuya estabilidad libera al improvisador." },
{ q: "La forma sonata comprende:", opts: ["Un solo tema desarrollado", "Exposición (temas A+B), Desarrollo, Reexposición", "Introducción y Coda solamente", "4 secciones de 8 compases"], a: 1, fb: "Forma sonata: Exposición = tema A (tónica) + tema B (dominante/relativo); Desarrollo = manipulación temática en tonalidades lejanas; Reexposición = A y B en tónica. La forma más teleológica del clasicismo." },
{ q: "En la forma sonata, el 'desarrollo' se caracteriza por:", opts: ["La repetición de la exposición", "La manipulación temática — fragmentar, modular — en tonalidades lejanas", "La introducción de nuevos temas", "La conclusión de la pieza"], a: 1, fb: "El desarrollo es la sección más inestable. Los temas de la exposición son fragmentados, transformados, transpuestos a tonalidades lejanas — es el 'viaje' entre la exposición (partida) y la reexposición (retorno). Beethoven sobresale en el arte del desarrollo." },
{ q: "¿Por qué la forma crea el sentido musical?", opts: ["Porque determina la duración", "Porque organiza el tiempo — sin forma, una sucesión de acordes no es más que una lista sin dirección ni sentido", "Porque fija el tempo", "Porque indica la instrumentación"], a: 1, fb: "La forma da una dirección al discurso musical. Sin forma, una sucesión de acordes está 'en el vacío' — no se sabe de dónde se viene ni adónde se va. La forma crea la expectativa (tensión) y su resolución (satisfacción): es la retórica de la música." },
{ q: "La forma copla-estribillo es:", opts: ["Idéntica a la forma sonata", "Alternancia entre coplas (contenido narrativo cambiante) y estribillo (melodía recurrente idéntica)", "Tres secciones idénticas", "Una forma únicamente instrumental"], a: 1, fb: "Copla-estribillo: las coplas narran (texto y a veces melodía variables); el estribillo regresa con el mismo texto y la misma melodía. Forma dominante de la canción popular (pop, rock, folk). Combina variedad (coplas) y recurrencia memorable (estribillo)." },
{ q: "La forma rondó es:", opts: ["ABA únicamente", "Un tema A que regresa alternadamente entre episodios contrastantes: ABACADA...", "Una forma jazz de 32 compases", "Dos secciones de desarrollo"], a: 1, fb: "El rondó alterna un estribillo (tema A) con episodios contrastantes (B, C, D...). El tema A (a menudo memorable) regresa como ancla entre aventuras musicales contrastantes. Muy presente en los finales de sonatas clásicas." },
{ q: "Schoenberg formalizó la noción de frase musical en:", opts: ["Die Kunst der Fuge", "Fundamentals of Musical Composition (redactado en los años 1930–40)", "El Clave bien temperado", "Tratado de orquestación de Berlioz"], a: 1, fb: "Arnold Schoenberg redactó Fundamentals of Musical Composition en los años 1930–40 en la UCLA, publicado póstumamente en 1967. Este tratado pedagógico analiza sistemáticamente la frase, el motivo, el período y las grandes formas — referencia fundamental para la enseñanza de la composición." },
{ q: "Schoenberg distingue dos tipos de marchas musicales:", opts: ["Marcha lenta y marcha rápida", "Marcha tonal (diatónica) y marcha real (transposición estricta, a veces cromática)", "Marcha ascendente y descendente", "Marcha simple y doble"], a: 1, fb: "Marcha tonal: el motivo se adapta a los intervalos de la escala diatónica. Marcha real: transposición estricta del mismo intervalo exacto (puede salir de la escala). Esta distinción es central en el análisis de Schoenberg — los dos tipos tienen efectos expresivos muy diferentes." },
{ q: "El concepto de 'liquidación' en Schoenberg designa:", opts: ["La supresión de acordes", "La eliminación progresiva de las características distintivas del motivo al final de la frase para señalar la cadencia", "Un cambio de tonalidad", "La reducción del número de voces"], a: 1, fb: "La liquidación es el proceso por el cual un motivo pierde progresivamente sus rasgos distintivos al final de la frase. Se conserva el ritmo, luego solo el contorno, luego casi nada — la frase se disuelve en la cadencia. Procedimiento retórico de 'conclusión' muy sofisticado." },
{ q: "Según Schoenberg, la repetición en la composición musical sirve para:", opts: ["Alargar una pieza sin esfuerzo", "Establecer la coherencia — el oyente reconoce lo que ya ha escuchado y puede seguir el discurso musical", "Compensar la falta de ideas", "Satisfacer las convenciones del género"], a: 1, fb: "Schoenberg insiste en la repetición como herramienta de coherencia (Verständlichkeit). Un motivo repetido (incluso transformado) es reconocible. La repetición crea la sensación de una idea desarrollada en lugar de una sucesión de ideas dispares — es la 'comprensibilidad' musical." },
{ q: "Schoenberg es paradójicamente también célebre por:", opts: ["Haber inventado la tonalidad", "Haber desarrollado el dodecafonismo — composición con los 12 semitonos en igualdad, sin tonalidad central", "Haber compuesto únicamente jazz", "Haber escrito óperas barrocas"], a: 1, fb: "Schoenberg es el teórico de la frase tonal Y el fundador del dodecafonismo (método de los 12 sonidos, 1921). Paradoja: su tratado analiza la forma tonal, pero su música (Pierrot Lunaire, Suite op.25) abole la tonalidad. Es el puente entre tradición y ruptura." },
{ q: "¿Qué distingue una progresión 'en el vacío' de una verdadera frase musical?", opts: ["El número de acordes", "La frase tiene un motivo conductor, una estructura de etapas y una cadencia — la progresión 'en el vacío' no tiene ni dirección ni conclusión", "La tonalidad", "El tempo"], a: 1, fb: "Una progresión 'en el vacío' = acordes encadenados sin lógica motivica ni cadencia premeditada. Una frase musical = motivo + desarrollo en 4 etapas + cadencia. La diferencia es la que existe entre una conversación (discurso estructurado) y una lista de palabras (ausencia de discurso)." },
{ q: "¿Cómo se reconoce una cadencia en una frase musical?", opts: ["Por un silencio", "Por un reposo en V (semicadencia) o I (cadencia perfecta) — momento de resolución de la tensión armónica", "Por un cambio de tempo", "Por una nota más aguda"], a: 1, fb: "La cadencia es un momento de reposo armónico. Semicadencia (V): pregunta suspendida. Cadencia perfecta (I): resolución completa. Cadencia plagal (IV–I): conclusión suave. Cadencia rota (V→VI): resolución engañosa. Cada tipo crea un efecto de puntuación diferente." },
{ q: "En un estándar jazz de forma AABA, el puente (B) sirve para:", opts: ["Repetir A", "Crear un contraste armónico y melódico que hace el retorno de A aún más satisfactorio", "Concluir la pieza", "Introducir al solista únicamente"], a: 1, fb: "El puente crea un contraste — a menudo en una tonalidad vecina, con un ritmo armónico o una dirección melódica opuesta a A. Este contraste hace el retorno final de A más esperado y más satisfactorio — 'se vuelve a casa'. Es la dialéctica tensión/resolución a escala formal." },
{ q: "La Sonata Patética de Beethoven es un ejemplo clásico de la frase de 8 compases porque:", opts: ["Dura 8 minutos", "Su primer tema ilustra las 4 etapas: idea de base, repetición, aceleración (liquidación), cadencia", "Solo tiene 8 compases", "Schoenberg la analizó en su tratado"], a: 1, fb: "El primer tema del Allegro de la Patética (op.13, 1798) ilustra las 4 etapas: motivo distintivo (comp. 1–2), repetición transformada (comp. 3–4), aceleración con liquidación (comp. 5–7), cadencia (comp. 8). Ejemplo pedagógico perfecto citado regularmente en los tratados de análisis." },
{ q: "¿Cómo están relacionadas la marcha armónica y la marcha melódica?", opts: ["Siempre son opuestas", "La marcha melódica repite un motivo a alturas sucesivas; la marcha armónica sostiene esas alturas con acordes que progresan en el mismo sentido", "Siempre son independientes", "La marcha armónica siempre precede a la melodía"], a: 1, fb: "En una marcha, melodía y armonía avanzan juntas: melodía C–E–G, D–F–A, E–G–B (marcha melódica ascendente) sobre acordes I, II, III (marcha armónica ascendente). Las dos dimensiones se mueven en paralelo — es lo que crea el efecto de progresión sostenida." },
{ q: "¿Por qué el blues de 12 compases se considera una forma musical?", opts: ["Porque siempre dura 12 segundos", "Porque tiene una estructura repetible y previsible (I7–IV7–I7–V7–I7) que crea expectativas y resoluciones en cada ciclo", "Porque solo contiene 3 acordes", "Porque proviene del Delta del Mississippi"], a: 1, fb: "El blues de 12 compases es una forma porque su estructura es previsible y compartida por músicos y oyentes. Esta previsibilidad es un recurso: el improvisador puede tocar 'sobre' la forma (contra las expectativas) o 'con' ella (confirmándolas). La forma = marco del discurso musical." },
{ q: "¿Cuál es la longitud típica de una frase musical en el repertorio clásico y jazz?", opts: ["4 compases", "8 compases", "12 compases", "16 compases"], a: 1, fb: "8 compases es la longitud estándar de la frase. Esta convención se estableció en el siglo XVIII y pasó al jazz (las secciones A y B de la forma AABA tienen cada una 8 compases). El período (antecedente + consecuente) tiene por tanto típicamente 16 compases (8+8)." },
{ q: "¿Qué es un 'tema' en relación con un 'motivo'?", opts: ["Un tema es más corto que un motivo", "El motivo es el elemento más pequeño; el tema es una idea más desarrollada (a menudo una frase entera) construida a partir de uno o varios motivos", "Un tema es armónico, un motivo es melódico", "Son sinónimos exactos"], a: 1, fb: "Motivo = célula mínima (4 notas). Tema = idea musical desarrollada (a menudo 8–16 compases) construida a partir de uno o varios motivos. El tema es memorable y 'cantable'; el motivo es el 'germen' generador. Beethoven extrae grandes temas de un solo motivo de 4 notas." },
{ q: "En la forma sonata clásica, la exposición presenta generalmente:", opts: ["Un solo tema", "Dos temas contrastantes — tema A (tónica) y tema B (dominante o relativo menor)", "Cuatro temas", "El desarrollo únicamente"], a: 1, fb: "La exposición presenta dos temas: A (tónica, a menudo enérgico) y B (dominante si mayor, relativo si menor — a menudo más lírico). Este contraste A/B crea la 'tensión dramática' que el desarrollo y la reexposición explorarán y resolverán." },
{ q: "Un 'motivo recurrente' en una gran forma (leitmotiv, idée fixe) sirve para:", opts: ["Repetir un pasaje de forma mecánica", "Crear una unidad a gran escala — el motivo reaparece en momentos clave para tejer la coherencia de toda la obra", "Facilitar la memorización del músico", "Indicar una modulación"], a: 1, fb: "El motivo recurrente crea la coherencia a gran escala. Wagner utiliza Leitmotive asociados a personajes que regresan a lo largo de una ópera. Berlioz inventa la idée fixe (Sinfonía Fantástica). Es la lógica de la forma ABA extendida a la escala de una obra entera." },
{ q: "La forma ABAC se utiliza notablemente en:", opts: ["El blues", "All The Things You Are, My Romance — estándares con dos segundas voltas diferentes (B luego C)", "La sinfonía clásica", "El rondó"], a: 1, fb: "ABAC: A regresa dos veces pero termina de forma diferente la segunda vez (C en lugar de B). All The Things You Are (Kern, 1939) es el ejemplo más célebre. Cada retorno de A es ligeramente diferente en su conclusión — ligera sorpresa a pesar de la recurrencia." },
{ q: "¿Por qué entender la forma es útil para un improvisador de jazz?", opts: ["Para respetar las convenciones", "Para saber dónde se está en la grilla — inicio o final de A, puente B, retorno final — y adaptar su interpretación en consecuencia", "Para leer la partitura", "Para tocar más notas"], a: 1, fb: "Un improvisador que conoce la forma toca 'con' la estructura: más tensión en el puente (B), resolución más marcada en el retorno de A, clímax colocado en el momento adecuado. Ignorar la forma equivale a improvisar 'en el vacío' — técnicamente correcto pero musicalmente inexpresivo." },
];

const questionsDe: Question[] = [{ q: "Was ist ein musikalisches Motiv?", opts: ["Ein Akkord aus 4 Tönen", "Das kleinste distinktive musikalische Element — der rote Faden des Diskurses einer Phrase", "Eine vollständige Tonleiter", "Ein Dominantakkord"], a: 1, fb: "Das Motiv ist das kleinste erkennbare und strukturierende musikalische Element. Es enthält die rhythmische und/oder melodische Identität, die wiederholt und transformiert wird. Beethoven baut seine gesamte 5. Sinfonie aus einem Motiv von nur 4 Noten (G–G–G–Eb)." },
{ q: "Das Motiv der 5. Sinfonie von Beethoven (G–G–G–Eb) verdeutlicht, dass:", opts: ["Ein Motiv lang sein muss, um ausdrucksstark zu sein", "Ein äußerst kurzes Motiv durch Wiederholung und Transformation einen vollständigen musikalischen Diskurs erzeugen kann", "Die 5. ausschließlich einen Moll-Modus verwendet", "Dieses Motiv aus einem Volkslied stammt"], a: 1, fb: "G–G–G–Eb: 4 Noten, 3 wiederholt + ein Terzfall. Dieses Motiv ist der Keim der gesamten 5. Sinfonie (1808). Beethoven fragmentiert es, transponiert es, vergrößert es — und zeigt damit, dass ein minimales Motiv zwanzig Minuten Musik aufbauen kann." },
{ q: "Was ist der Unterschied zwischen 'Begleitmusik' und 'Diskursmusik'?", opts: ["Begleitmusik ist länger", "Begleitmusik begleitet eine äußere Handlung; Diskursmusik entwickelt ihre eigenen musikalischen Ideen autonom", "Diskursmusik ist kürzer", "Es gibt keinen Unterschied"], a: 1, fb: "Begleitmusik (Film, Ballett) dient einer äußeren Handlung — ihre Struktur kann entsprechend der Erzählung fragmentiert sein. Diskursmusik (Sonate, Fuge, Jazz-Standard) entwickelt ihre eigenen Ideen logisch und autonom, unabhängig von jedem extra-musikalischen Kontext." },
{ q: "Der rote Faden einer musikalischen Phrase ist:", opts: ["Die Tonalität", "Das Motiv — wiederholt und transformiert, um der Phrase Kohärenz zu verleihen", "Das Tempo", "Die Begleitung"], a: 1, fb: "Das Motiv ist der rote Faden. Seine Wiederholung (streng oder transformiert) schafft Kohärenz. Der Hörer erkennt das Motiv auch in transformierter Form — das ist es, was den Eindruck eines zusammenhängenden musikalischen Diskurses statt einer Abfolge disparater Ideen erzeugt." },
{ q: "Aus wie vielen Schritten besteht eine typische musikalische Phrase von 8 Takten?", opts: ["2", "3", "4", "8"], a: 2, fb: "Die 8-Takt-Phrase folgt 4 Schritten: (1) Grundidee, (2) Wiederholung, (3) Beschleunigung/Fragmentierung, (4) Kadenz. Dieses Schema findet sich bei Beethoven, Mozart, Haydn und in den meisten Jazz-Standard-Formen." },
{ q: "Was ist der erste Schritt einer musikalischen Phrase?", opts: ["Die Kadenz", "Die Grundidee — Präsentation des Hauptmotivs", "Die Wiederholung", "Die Liquidation"], a: 1, fb: "Die Grundidee ist die Formulierung des 'Themas' der Phrase: Präsentation des Motivs oder der motivischen Zelle. Die 3 folgenden Schritte (Wiederholung, Beschleunigung, Kadenz) ergeben sich aus dieser Anfangsidee." },
{ q: "Was bezeichnet die 'Liquidation' einer Phrase (Schoenbergs Begriff)?", opts: ["Das Motiv langsamer wiederholen", "Das harmonische Rhythmus am Ende der Phrase beschleunigen — die Harmonien wechseln schneller, um die bevorstehende Kadenz anzuzeigen", "Die Anzahl der Instrumente reduzieren", "Leiser spielen"], a: 1, fb: "Die Liquidation bezeichnet die Beschleunigung des harmonischen Rhythmus am Ende einer Phrase. Harmonien, die alle 2 Takte wechselten, wechseln nun jeden Takt, dann auf jedem Schlag — ein rhetorisches Signal, dass die Kadenz naht: 'Der Schluss kommt'." },
{ q: "Im 3. Schritt einer Beethoven-Phrase manifestiert sich die Beschleunigung durch:", opts: ["Ein schnelleres Tempo", "Fragmentierte Motive und einen dichteren harmonischen Rhythmus, der vor der Kadenz Spannung erzeugt", "Einen Instrumentenwechsel", "Eine tiefere Melodie"], a: 1, fb: "Die Beschleunigung im 3. Schritt = Fragmentierung des Motivs und Verdichtung des harmonischen Rhythmus. Beethoven wiederholt zunehmend kürzere Motivfragmente, die Akkorde wechseln immer schneller — Spannung, die die Schlusskadenz 'herbeisehnt'." },
{ q: "Was ist die 'strenge Wiederholung' eines Motivs?", opts: ["In einer anderen Tonart wiederholen", "Das Motiv identisch wiederholen — gleiche Tonhöhen, gleicher Rhythmus", "Mit Verzierungen wiederholen", "Nur eine Oktave tiefer wiederholen"], a: 1, fb: "Die strenge Wiederholung reproduziert das Motiv exakt. Die direkteste Technik: Der Hörer erkennt das Motiv sofort. Sie kann mechanisch wirken; deshalb wird sie oft mit anderen Transformationstechniken kombiniert." },
{ q: "Die 'melodische Transformation' eines Motivs besteht darin:", opts: ["Seinen Rhythmus zu ändern", "Das Motiv auf eine andere Tonhöhe zu transponieren, während das gleiche rhythmische Profil beibehalten wird", "Die Intervalle umzukehren", "Das Motiv rückwärts zu spielen"], a: 1, fb: "Die melodische Transformation transponiert das Motiv — das rhythmische Profil bleibt identisch, die Tonhöhen ändern sich. C–E–G wird zu D–F–A (einen Ton höher). Die rhythmische Identität wahrt die Kohärenz; die neue Tonhöhe bringt Abwechslung." },
{ q: "Eine musikalische 'Marche' (oder Sequenz) ist:", opts: ["Ein militärischer Marschrhythmus", "Ein Motiv, das auf aufeinanderfolgenden Stufen der Tonleiter oder durch chromatische Transposition wiederholt wird", "Ein Durchgangsakkord", "Eine Form von 16 Takten"], a: 1, fb: "Die Marche (Sequenz) wiederholt ein Motiv auf aufeinanderfolgenden Tonhöhen. Tonale Marche: bleibt in der diatonischen Tonleiter. Reale Marche (chromatisch): transponiert streng das gleiche Intervall (kann die Tonleiter verlassen). Bsp. C–E–G, D–F–A, E–G–B (aufsteigende tonale Marche)." },
{ q: "Der Unterschied zwischen 'tonaler Marche' und 'realer Marche' ist:", opts: ["Das Tempo", "Die tonale Marche bleibt diatonisch (Intervalle leicht angepasst); die reale Marche transponiert streng dasselbe Intervall und erzeugt Chromatik", "Die reale Marche ist länger", "Es gibt keinen Unterschied"], a: 1, fb: "Schoenbergs Schlüsselunterscheidung: tonale Marche = das Motiv passt sich den Intervallen der Tonleiter an (kann das Intervall leicht verändern); reale Marche = strenge Transposition desselben Intervalls (kann leiterfremde Töne einführen)." },
{ q: "Ein 'komplementäres Motiv' ist:", opts: ["Ein Motiv, das das Hauptmotiv im Einklang imitiert", "Ein zweites Motiv, das dem ersten antwortet und den rhythmischen oder melodischen Raum der Phrase vervollständigt", "Ein umgekehrtes Motiv", "Ein gleichzeitig gespieltes Motiv"], a: 1, fb: "Das komplementäre Motiv antwortet dem Hauptmotiv — oft in den folgenden Takten. Bsp. Motiv A (Takte 1–2) + Motiv B (Takte 3–4). Zusammen bilden A und B die vollständige Phrase; jedes ist ohne das andere unvollständig." },
{ q: "Die 'melodisch-harmonische Transformation' besteht darin:", opts: ["Rhythmus und Melodie zu ändern", "Den melodischen Umriss des Motivs beizubehalten, aber die darunter liegenden Akkorde zu ändern und damit die harmonische Farbe zu verändern", "Melodie und Akkorde umzukehren", "In alle 12 Tonarten zu transponieren"], a: 1, fb: "Die melodisch-harmonische Transformation bewahrt den erkennbaren melodischen Umriss, ändert aber die darunter liegenden Akkorde. Die Melodie C–E–G klingt auf I (CMaj7) anders als auf VI (Am7). Die Melodie schafft Kohärenz; die Harmonie erneuert den Ausdruck." },
{ q: "Was ist eine musikalische Periode?", opts: ["Eine Phrase von 4 Takten", "Eine Struktur aus zwei Phrasen: Vordersatz (schwache Kadenz) + Nachsatz (starke Kadenz)", "Eine Gruppe von 3 Phrasen", "Ein Abschnitt von 32 Takten"], a: 1, fb: "Die Periode ist zweiteilig: Der Vordersatz (Phrase 1) endet auf einer schwachen Kadenz (oft V — Halbkadenz) und erzeugt eine Frage. Der Nachsatz (Phrase 2) endet auf einer starken Kadenz (I — authentische Kadenz) und liefert die Antwort. Typische Länge: 16 Takte (8+8)." },
{ q: "Der Vordersatz einer Periode endet auf:", opts: ["Der Tonika (I) — authentische Kadenz", "Der Dominante (V) — Halbkadenz, Wirkung einer schwebenden Frage", "Der Subdominante (IV)", "Der Mediante (III)"], a: 1, fb: "Der Vordersatz endet auf V (Halbkadenz) — das Ohr erwartet einen Abschluss. Das ist die 'Frage'. Der Nachsatz antwortet mit einer Beendigung auf I. Dieses Frage/Antwort-Schema ist die grundlegende rhetorische Struktur der tonalen Musik." },
{ q: "Der Nachsatz einer Periode endet auf:", opts: ["Der Dominante (V)", "Der Tonika (I) — authentische Kadenz, Schluss", "Der Subdominante (IV)", "Einem Septakkord"], a: 1, fb: "Der Nachsatz endet auf I (authentische Kadenz). Nach der 'Frage' des Vordersatzes (der auf V endet) liefert der Nachsatz die abschließende 'Antwort', indem er auf der Tonika verankert. Das ist die natürlichste musikalische Rhetorik." },
{ q: "Der Hauptunterschied zwischen einer Phrase und einer Periode ist:", opts: ["Nur die Länge", "Die Phrase = eine autonome Einheit (8 T.) mit ihrer Kadenz; die Periode = zwei Phrasen (Vordersatz + Nachsatz, 16 T.) mit schwacher dann starker Kadenz", "Die Anzahl der Motive", "Die Tonalität"], a: 1, fb: "Die Phrase ist eine autonome Einheit (typisch 8 Takte) mit ihrer eigenen Kadenz. Die Periode ist eine Struktur aus zwei Phrasen: Vordersatz (Kadenz V — Frage) + Nachsatz (Kadenz I — Antwort). Die Periode umfasst daher typisch 16 Takte." },
{ q: "Vordersatz und Nachsatz teilen oft:", opts: ["Exakt dieselben Noten", "Dasselbe thematische Ausgangsmaterial — durch ein gemeinsames Anfangsmotiv verbunden, aber unterschiedlich abgeschlossen", "Dasselbe Tempo", "Absolut dieselbe Dauer"], a: 1, fb: "Vordersatz und Nachsatz beginnen oft mit demselben Motiv — das ist es, was sie zu einer kohärenten Periode vereint. Aber ihre Schlüsse unterscheiden sich: Kadenz V (Vordersatz) vs. Kadenz I (Nachsatz). Gleicher Anfang, kontrastierende Schlüsse: Frage/Antwort." },
{ q: "Der 'Frage/Antwort'-Effekt in einer Periode wird erzeugt durch:", opts: ["Zwei verschiedene Motive", "Die schwache Kadenz des Vordersatzes (V), die Erwartung weckt, aufgelöst durch die starke Kadenz des Nachsatzes (I)", "Den Tempowechsel", "Die Lautstärkesteigerung"], a: 1, fb: "V (Halbkadenz) = schwebende Frage. I (authentische Kadenz) = abschließende Antwort. Dieses Frage/Antwort-Schema auf der Ebene der Periode spiegelt dieselbe Logik wie Spannung/Auflösung auf der Akkordebene (Tritonus von V7 → Auflösung nach I). Gleiches Prinzip, größerer Maßstab." },
{ q: "Was ist die ABA-Form?", opts: ["3 identische Abschnitte", "Abschnitt A (Hauptthema) — kontrastierender Abschnitt B — Rückkehr von A", "A zweimal wiederholt, dann B", "Eine Form von 32 Takten"], a: 1, fb: "Die ABA-Form (Lied) präsentiert A (Hauptthema), kontrastierendes B (neue Tonart oder Modus), dann die Rückkehr von A. Die Symmetrie A–B–A schafft Gleichgewicht und Befriedigung: man bricht auf, man kehrt zurück. Allgegenwärtig in Chopins Nocturnes und Opern-Arien." },
{ q: "Die AABA-Form von 32 Takten ist:", opts: ["4 identische Abschnitte", "A (8 T.) 2-mal wiederholt, Brücke B (8 T.) kontrastierend, Rückkehr von A (8 T.)", "A 4-mal wiederholt", "Eine ausschließlich klassische Form"], a: 1, fb: "AABA = 32 Takte: A (8) + A (8) + Brücke B (8) + A (8). Die Brücke B steht oft in einer benachbarten Tonart oder mit einem anderen harmonischen Rhythmus. Das ist die Standardform der amerikanischen Jazz-Standards der 1930er–60er Jahre." },
{ q: "In der AABA-Form wird der Abschnitt B genannt:", opts: ["Coda", "Brücke (Bridge)", "Refrain", "Durchführung"], a: 1, fb: "Der Abschnitt B in einer AABA-Form ist die 'Brücke' (Bridge). Er kontrastiert mit A durch Tonart, harmonischen Rhythmus oder Textur. Die Brücke schafft die nötige Abwechslung vor der abschließenden Rückkehr von A — 'man kehrt nach Hause zurück'." },
{ q: "Autumn Leaves verwendet welche Form?", opts: ["ABA", "AABA", "ABAB", "Blues 12 Takte"], a: 1, fb: "Autumn Leaves (Kosma, 1945) ist in der AABA-Form mit 32 Takten. Es ist einer der am häufigsten gespielten Standards zur Vermittlung der Jazz-Form — seine zwei aufeinanderfolgenden II–V–I (Dur und Moll) im A-Abschnitt machen es auch zu einem Musterbeispiel für typische Progressionen." },
{ q: "Der 12-Takt-Blues ist strukturiert um:", opts: ["I–V–I nur", "I7 (4 T.) – IV7 (2 T.) – I7 (2 T.) – II–V–I (4 T.)", "16 gleiche Takte", "Zwei Abschnitte von 6 Takten"], a: 1, fb: "Blues 12 Takte: I7 (4 T.) | IV7 (2 T.) | I7 (2 T.) | Turnaround (4 T.). Frage/Antwort/Auflösungs-Struktur im Maßstab von 12 Takten. Eine vorhersehbare Form, deren Stabilität den Improvisator befreit." },
{ q: "Die Sonatenform umfasst:", opts: ["Ein einziges entwickeltes Thema", "Exposition (Themen A+B), Durchführung, Reprise", "Nur Einleitung und Coda", "4 Abschnitte von 8 Takten"], a: 1, fb: "Sonatenform: Exposition = Thema A (Tonika) + Thema B (Dominante/Relative); Durchführung = thematische Verarbeitung in entfernten Tonarten; Reprise = A und B in der Tonika. Die teleologischste Form des Klassizismus." },
{ q: "In der Sonatenform ist die 'Durchführung' gekennzeichnet durch:", opts: ["Die Wiederholung der Exposition", "Die thematische Verarbeitung — Fragmentierung, Modulation — in entfernten Tonarten", "Die Einführung neuer Themen", "Den Schluss des Stückes"], a: 1, fb: "Die Durchführung ist der instabilste Abschnitt. Die Themen der Exposition werden fragmentiert, transformiert, in entfernte Tonarten transponiert — das ist die 'Reise' zwischen Exposition (Aufbruch) und Reprise (Rückkehr). Beethoven glänzt in der Kunst der Durchführung." },
{ q: "Warum erzeugt die Form den musikalischen Sinn?", opts: ["Weil sie die Dauer bestimmt", "Weil sie die Zeit organisiert — ohne Form ist eine Akkordfolge nur eine Liste ohne Richtung oder Sinn", "Weil sie das Tempo festlegt", "Weil sie die Instrumentation angibt"], a: 1, fb: "Die Form gibt dem musikalischen Diskurs eine Richtung. Ohne Form ist eine Akkordfolge 'bodenlos' — man weiß weder woher man kommt noch wohin man geht. Die Form erzeugt Erwartung (Spannung) und deren Auflösung (Befriedigung): das ist die Rhetorik der Musik." },
{ q: "Die Strophe-Refrain-Form ist:", opts: ["Identisch mit der Sonatenform", "Wechsel zwischen Strophen (wechselnder erzählerischer Inhalt) und Refrain (identisch wiederkehrende Melodie)", "Drei identische Abschnitte", "Eine ausschließlich instrumentale Form"], a: 1, fb: "Strophe-Refrain: Die Strophen erzählen (variabler Text und manchmal Melodie); der Refrain kehrt mit demselben Text und derselben Melodie zurück. Dominante Form des Popsongs (Pop, Rock, Folk). Sie verbindet Abwechslung (Strophen) mit einprägsamer Wiederkehr (Refrain)." },
{ q: "Die Rondoform ist:", opts: ["Nur ABA", "Ein Thema A, das abwechselnd zwischen kontrastierenden Episoden zurückkehrt: ABACADA...", "Eine Jazz-Form von 32 Takten", "Zwei Durchführungsabschnitte"], a: 1, fb: "Das Rondo wechselt zwischen einem Kehrreim (Thema A) und kontrastierenden Episoden (B, C, D...). Das Thema A (oft einprägsam) kehrt als Anker zwischen kontrastierenden musikalischen Abenteuern zurück. Sehr verbreitet in Finalsätzen klassischer Sonaten." },
{ q: "Schoenberg formalisierte den Begriff der musikalischen Phrase in:", opts: ["Die Kunst der Fuge", "Fundamentals of Musical Composition (verfasst in den 1930er–40er Jahren)", "Das Wohltemperierte Klavier", "Berlioz' Instrumentationslehre"], a: 1, fb: "Arnold Schoenberg verfasste Fundamentals of Musical Composition in den 1930er–40er Jahren an der UCLA, posthum veröffentlicht 1967. Dieses pädagogische Werk analysiert systematisch Phrase, Motiv, Periode und die großen Formen — grundlegende Referenz für den Kompositionsunterricht." },
{ q: "Schoenberg unterscheidet zwei Arten von musikalischen Marches:", opts: ["Langsame und schnelle Marche", "Tonale Marche (diatonisch) und reale Marche (strenge Transposition, manchmal chromatisch)", "Aufsteigende und absteigende Marche", "Einfache und doppelte Marche"], a: 1, fb: "Tonale Marche: das Motiv passt sich den Intervallen der diatonischen Tonleiter an. Reale Marche: strenge Transposition desselben exakten Intervalls (kann die Tonleiter verlassen). Diese Unterscheidung ist zentral in Schoenbergs Analyse — beide Typen haben sehr unterschiedliche expressive Wirkungen." },
{ q: "Das Konzept der 'Liquidation' bei Schoenberg bezeichnet:", opts: ["Die Streichung von Akkorden", "Die schrittweise Eliminierung der distinktiven Merkmale des Motivs am Ende einer Phrase, um die Kadenz anzuzeigen", "Einen Tonartenwechsel", "Die Reduzierung der Stimmenzahl"], a: 1, fb: "Die Liquidation ist der Prozess, durch den ein Motiv am Ende einer Phrase schrittweise seine distinktiven Merkmale verliert. Man behält den Rhythmus, dann nur noch den Umriss, dann fast nichts — die Phrase löst sich in der Kadenz auf. Ein sehr ausgefeilter rhetorischer 'Schluss'-Prozess." },
{ q: "Laut Schoenberg dient die Wiederholung in der musikalischen Komposition dazu:", opts: ["Ein Stück mühelos zu verlängern", "Kohärenz herzustellen — der Hörer erkennt, was er bereits gehört hat, und kann dem musikalischen Diskurs folgen", "Mangel an Ideen auszugleichen", "Den Konventionen des Genres zu entsprechen"], a: 1, fb: "Schoenberg betont die Wiederholung als Mittel der Kohärenz (Verständlichkeit). Ein wiederholtes Motiv (auch transformiert) ist erkennbar. Die Wiederholung erzeugt das Gefühl einer entwickelten Idee statt einer Abfolge disparater Ideen — das ist die musikalische 'Verständlichkeit'." },
{ q: "Schoenberg ist paradoxerweise auch berühmt für:", opts: ["Die Erfindung der Tonalität", "Die Entwicklung des Dodekaphonismus — Komposition mit allen 12 Halbtönen gleichberechtigt, ohne zentrale Tonalität", "Ausschließlich Jazz komponiert zu haben", "Barocke Opern geschrieben zu haben"], a: 1, fb: "Schoenberg ist der Theoretiker der tonalen Phrase UND der Begründer des Dodekaphonismus (Zwölftontechnik, 1921). Paradox: Sein Traktat analysiert die tonale Form, aber seine Musik (Pierrot Lunaire, Suite op.25) hebt die Tonalität auf. Er ist die Brücke zwischen Tradition und Bruch." },
{ q: "Was unterscheidet eine 'bodenlose' Progression von einer echten musikalischen Phrase?", opts: ["Die Anzahl der Akkorde", "Die Phrase hat ein leitendes Motiv, eine Stufenstruktur und eine Kadenz — die 'bodenlose' Progression hat weder Richtung noch Schluss", "Die Tonalität", "Das Tempo"], a: 1, fb: "Eine 'bodenlose' Progression = aneinandergereihte Akkorde ohne motivische Logik oder vorgesehene Kadenz. Eine musikalische Phrase = Motiv + Entwicklung in 4 Schritten + Kadenz. Der Unterschied ist der zwischen einem Gespräch (strukturierter Diskurs) und einer Wortliste (kein Diskurs)." },
{ q: "Woran erkennt man eine Kadenz in einer musikalischen Phrase?", opts: ["An einer Pause", "An einer Ruhestelle auf V (Halbkadenz) oder I (authentische Kadenz) — Moment der Auflösung der harmonischen Spannung", "An einem Tempowechsel", "An einer höheren Note"], a: 1, fb: "Die Kadenz ist ein harmonischer Ruhepunkt. Halbkadenz (V): schwebende Frage. Authentische Kadenz (I): vollständige Auflösung. Plagalkadenz (IV–I): sanfter Abschluss. Trugschluss (V→VI): täuschende Auflösung. Jeder Typ erzeugt einen anderen Interpunktionseffekt." },
{ q: "In einem Jazz-Standard der AABA-Form dient die Brücke (B) dazu:", opts: ["A zu wiederholen", "Einen harmonischen und melodischen Kontrast zu schaffen, der die Rückkehr von A umso befriedigender macht", "Das Stück abzuschließen", "Ausschließlich den Solisten einzuführen"], a: 1, fb: "Die Brücke schafft Kontrast — oft in einer benachbarten Tonart, mit einem harmonischen Rhythmus oder einer melodischen Richtung, die A entgegengesetzt ist. Dieser Kontrast macht die abschließende Rückkehr von A erwarteter und befriedigender — 'man kehrt nach Hause zurück'. Das ist die Dialektik Spannung/Auflösung auf formaler Ebene." },
{ q: "Die Pathétique-Sonate von Beethoven ist ein klassisches Beispiel der 8-Takt-Phrase, weil:", opts: ["Sie 8 Minuten dauert", "Ihr erstes Thema die 4 Schritte veranschaulicht: Grundidee, Wiederholung, Beschleunigung (Liquidation), Kadenz", "Sie nur 8 Takte hat", "Schoenberg sie in seinem Traktat analysiert hat"], a: 1, fb: "Das erste Thema des Allegro der Pathétique (op.13, 1798) veranschaulicht die 4 Schritte: markantes Motiv (T. 1–2), transformierte Wiederholung (T. 3–4), Beschleunigung mit Liquidation (T. 5–7), Kadenz (T. 8). Ein perfektes pädagogisches Beispiel, das regelmäßig in Analysetraktaten zitiert wird." },
{ q: "Wie sind harmonische Marche und melodische Marche miteinander verbunden?", opts: ["Sie sind immer entgegengesetzt", "Die melodische Marche wiederholt ein Motiv auf aufeinanderfolgenden Tonhöhen; die harmonische Marche stützt diese Tonhöhen durch Akkorde, die in dieselbe Richtung fortschreiten", "Sie sind immer unabhängig", "Die harmonische Marche geht der Melodie immer voraus"], a: 1, fb: "In einer Marche schreiten Melodie und Harmonie gemeinsam voran: Melodie C–E–G, D–F–A, E–G–B (aufsteigende melodische Marche) über Akkorde I, II, III (aufsteigende harmonische Marche). Beide Dimensionen bewegen sich parallel — das erzeugt den Effekt einer anhaltenden Progression." },
{ q: "Warum gilt der 12-Takt-Blues als musikalische Form?", opts: ["Weil er immer 12 Sekunden dauert", "Weil er eine wiederholbare und vorhersehbare Struktur hat (I7–IV7–I7–V7–I7), die bei jedem Zyklus Erwartungen und Auflösungen schafft", "Weil er nur 3 Akkorde enthält", "Weil er aus dem Mississippi-Delta stammt"], a: 1, fb: "Der 12-Takt-Blues ist eine Form, weil seine Struktur von Musikern und Hörern geteilt und vorhergesagt wird. Diese Vorhersehbarkeit ist eine Ressource: Der Improvisator kann 'gegen' die Form spielen (gegen die Erwartungen) oder 'mit' ihr (sie bestätigend). Die Form = Rahmen des musikalischen Diskurses." },
{ q: "Was ist die typische Länge einer musikalischen Phrase im klassischen und Jazz-Repertoire?", opts: ["4 Takte", "8 Takte", "12 Takte", "16 Takte"], a: 1, fb: "8 Takte ist die Standardlänge der Phrase. Diese Konvention etablierte sich im 18. Jahrhundert und fand Eingang in den Jazz (die A- und B-Abschnitte der AABA-Form umfassen je 8 Takte). Die Periode (Vordersatz + Nachsatz) umfasst daher typisch 16 Takte (8+8)." },
{ q: "Was ist ein 'Thema' im Vergleich zu einem 'Motiv'?", opts: ["Ein Thema ist kürzer als ein Motiv", "Das Motiv ist das kleinste Element; das Thema ist eine ausgefeiltere Idee (oft eine ganze Phrase), die aus einem oder mehreren Motiven besteht", "Ein Thema ist harmonisch, ein Motiv ist melodisch", "Sie sind genaue Synonyme"], a: 1, fb: "Motiv = minimale Zelle (4 Noten). Thema = entwickelte musikalische Idee (oft 8–16 Takte), aufgebaut aus einem oder mehreren Motiven. Das Thema ist einprägsam und 'spielbar'; das Motiv ist der 'Keim'. Beethoven entwickelt große Themen aus einem einzigen 4-Noten-Motiv." },
{ q: "In der klassischen Sonatenform präsentiert die Exposition gewöhnlich:", opts: ["Ein einziges Thema", "Zwei kontrastierende Themen — Thema A (Tonika) und Thema B (Dominante oder relatives Moll)", "Vier Themen", "Nur die Durchführung"], a: 1, fb: "Die Exposition präsentiert zwei Themen: A (Tonika, oft energisch) und B (Dominante wenn Dur, Relative wenn Moll — oft lyrischer). Dieser A/B-Kontrast schafft die 'dramatische Spannung', die Durchführung und Reprise erkunden und auflösen werden." },
{ q: "Ein 'wiederkehrendes Motiv' in einer großen Form (Leitmotiv, Idée fixe) dient dazu:", opts: ["Einen Abschnitt mechanisch zu wiederholen", "Einheit im großen Maßstab zu schaffen — das Motiv erscheint an Schlüsselmomenten wieder, um die Kohärenz des gesamten Werkes zu weben", "Die Memorierung des Musikers zu erleichtern", "Eine Modulation anzuzeigen"], a: 1, fb: "Das wiederkehrende Motiv schafft Kohärenz im großen Maßstab. Wagner verwendet Leitmotive, die mit Figuren assoziiert sind und sich durch eine ganze Oper hindurchziehen. Berlioz erfindet die Idée fixe (Symphonie Fantastique). Das ist die Logik der ABA-Form auf den Maßstab eines ganzen Werkes ausgedehnt." },
{ q: "Die ABAC-Form wird besonders verwendet in:", opts: ["Dem Blues", "All The Things You Are, My Romance — Standards mit zwei verschiedenen zweiten Volten (B dann C)", "Der klassischen Sinfonie", "Dem Rondo"], a: 1, fb: "ABAC: A kehrt zweimal zurück, endet aber beim zweiten Mal anders (C statt B). All The Things You Are (Kern, 1939) ist das berühmteste Beispiel. Jede Rückkehr von A unterscheidet sich leicht in seinem Abschluss — leichte Überraschung trotz der Wiederkehr." },
{ q: "Warum ist das Verstehen von Form für einen Jazz-Improvisator nützlich?", opts: ["Um Konventionen zu respektieren", "Um zu wissen, wo man in der Akkordfolge steht — Anfang oder Ende von A, Brücke B, letzter Rückkehr — und das Spiel entsprechend anzupassen", "Um die Partitur zu lesen", "Um mehr Noten zu spielen"], a: 1, fb: "Ein Improvisator, der die Form kennt, spielt 'mit' der Struktur: mehr Spannung an der Brücke (B), markantere Auflösung bei der Rückkehr von A, Klimax zur richtigen Zeit. Die Form zu ignorieren bedeutet, 'im Leeren' zu improvisieren — technisch korrekt, aber musikalisch ausdruckslos." },
];

const questionsIt: Question[] = [
{ q: "Che cos'è un motivo musicale?", opts: ["Un accordo di 4 suoni", "Il più piccolo elemento musicale distintivo — filo conduttore del discorso di una frase", "Una scala completa", "Un accordo di dominante"], a: 1, fb: "Il motivo è il più piccolo elemento musicale riconoscibile e strutturante. Contiene l'identità ritmica e/o melodica che sarà ripetuta e trasformata. Beethoven costruisce tutta la sua 5ª Sinfonia a partire da un motivo di sole 4 note (Sol–Sol–Sol–Mib)." },
{ q: "Il motivo della 5ª Sinfonia di Beethoven (Sol–Sol–Sol–Mib) illustra che:", opts: ["Un motivo deve essere lungo per essere espressivo", "Un motivo estremamente breve può generare un discorso musicale completo attraverso ripetizione e trasformazione", "La 5ª utilizza esclusivamente un modo minore", "Questo motivo proviene da una canzone popolare"], a: 1, fb: "Sol–Sol–Sol–Mib: 4 note, 3 ripetute + una caduta di terza. Questo motivo è il germe dell'intera 5ª Sinfonia (1808). Beethoven lo frammenta, lo traspone, lo amplia — dimostrando che un motivo minimo può costruire venti minuti di musica." },
{ q: "Qual è la differenza tra 'musica di supporto' e 'musica di discorso'?", opts: ["La musica di supporto è più lunga", "La musica di supporto accompagna un'azione esterna; la musica di discorso sviluppa le proprie idee musicali in modo autonomo", "La musica di discorso è più breve", "Non c'è nessuna differenza"], a: 1, fb: "La musica di supporto (cinema, balletto) serve un'azione esterna — la sua struttura può essere frammentata secondo la narrazione. La musica di discorso (sonata, fuga, standard jazz) sviluppa le proprie idee in modo logico e autonomo, indipendentemente da qualsiasi contesto extra-musicale." },
{ q: "Il filo conduttore di una frase musicale è:", opts: ["La tonalità", "Il motivo — ripetuto e trasformato per dare coerenza alla frase", "Il tempo", "L'accompagnamento"], a: 1, fb: "Il motivo è il filo conduttore. La sua ripetizione (stretta o trasformata) crea coerenza. L'ascoltatore riconosce il motivo anche trasformato — è ciò che dà l'impressione di un discorso musicale continuo piuttosto che una successione di idee disparate." },
{ q: "Quante fasi ha una frase musicale tipica di 8 misure?", opts: ["2", "3", "4", "8"], a: 2, fb: "La frase di 8 misure segue 4 fasi: (1) idea di base, (2) ripetizione, (3) accelerazione/frammentazione, (4) cadenza. Questo schema è presente in Beethoven, Mozart, Haydn e nella maggior parte delle forme jazz standard." },
{ q: "Qual è la prima fase di una frase musicale?", opts: ["La cadenza", "L'idea di base — presentazione del motivo principale", "La ripetizione", "La liquidazione"], a: 1, fb: "L'idea di base è l'enunciazione del 'soggetto' della frase: presentazione del motivo o della cellula motivica. Le 3 fasi successive (ripetizione, accelerazione, cadenza) derivano da questa idea iniziale." },
{ q: "Che cos'è la 'liquidazione' di una frase (termine di Schoenberg)?", opts: ["Ripetere il motivo più lentamente", "Accelerare il ritmo armonico alla fine della frase — le armonie cambiano più velocemente per segnalare la cadenza imminente", "Ridurre il numero degli strumenti", "Suonare meno forte"], a: 1, fb: "La liquidazione designa l'accelerazione del ritmo armonico alla fine della frase. Le armonie che cambiavano ogni 2 misure ora cambiano ogni misura, poi ad ogni tempo — segnale retorico che la cadenza si avvicina: 'la conclusione sta arrivando'." },
{ q: "Nella 3ª fase di una frase di Beethoven, l'accelerazione si manifesta attraverso:", opts: ["Un tempo più rapido", "Motivi frammentati e un ritmo armonico più denso, creando tensione prima della cadenza", "Un cambio di strumento", "Una melodia più grave"], a: 1, fb: "L'accelerazione della 3ª fase = frammentazione del motivo e densificazione del ritmo armonico. Beethoven ripete frammenti di motivo sempre più brevi, gli accordi cambiano sempre più velocemente — tensione che 'chiama' la cadenza finale." },
{ q: "Che cos'è la 'ripetizione stretta' di un motivo?", opts: ["Ripetere in un'altra tonalità", "Ripetere il motivo in modo identico — stesse altezze, stesso ritmo", "Ripetere con ornamenti", "Ripetere solo all'ottava inferiore"], a: 1, fb: "La ripetizione stretta riproduce il motivo esattamente. La tecnica più diretta: l'ascoltatore riconosce immediatamente il motivo. Può sembrare meccanica; è per questo che viene spesso combinata con altre tecniche di trasformazione." },
{ q: "La 'trasformazione melodica' di un motivo consiste nel:", opts: ["Cambiare il suo ritmo", "Trasporre il motivo a un'altra altezza mantenendo lo stesso contorno ritmico", "Invertire gli intervalli", "Suonare il motivo al contrario"], a: 1, fb: "La trasformazione melodica traspone il motivo — il contorno ritmico rimane identico, le altezze cambiano. Do–Mi–Sol diventa Re–Fa–La (un tono più in alto). L'identità ritmica mantiene la coerenza; la nuova altezza porta varietà." },
{ q: "Una 'marcia' (o sequenza) musicale è:", opts: ["Un ritmo di marcia militare", "Un motivo ripetuto a gradi successivi della scala o per trasposizione cromatica", "Un accordo di passaggio", "Una forma di 16 misure"], a: 1, fb: "La marcia (sequenza) ripete un motivo ad altezze successive. Marcia tonale: rimane nella scala diatonica. Marcia reale (cromatica): traspone strettamente lo stesso intervallo (può uscire dalla scala). Es. Do–Mi–Sol, Re–Fa–La, Mi–Sol–Si (marcia tonale ascendente)." },
{ q: "La differenza tra 'marcia tonale' e 'marcia reale' è:", opts: ["Il tempo", "La marcia tonale rimane diatonica (intervalli leggermente adattati); la marcia reale traspone strettamente lo stesso intervallo, creando cromatismi", "La marcia reale è più lunga", "Non c'è nessuna differenza"], a: 1, fb: "Distinzione chiave di Schoenberg: marcia tonale = il motivo si adatta agli intervalli della scala (può cambiare leggermente l'intervallo); marcia reale = trasposizione stretta dello stesso intervallo (può introdurre note estranee alla scala)." },
{ q: "Un motivo 'complementare' è:", opts: ["Un motivo che imita il principale all'unisono", "Un secondo motivo che risponde al primo, completando lo spazio ritmico o melodico della frase", "Un motivo invertito", "Un motivo suonato simultaneamente"], a: 1, fb: "Il motivo complementare risponde al motivo principale — spesso nelle misure successive. Es. Motivo A (misure 1–2) + Motivo B (misure 3–4). Insieme, A e B formano la frase completa; ciascuno è incompleto senza l'altro." },
{ q: "La 'trasformazione melodico-armonica' consiste nel:", opts: ["Cambiare il ritmo e la melodia", "Mantenere il contorno melodico del motivo ma cambiare gli accordi sottostanti, modificando il colore armonico", "Invertire la melodia e gli accordi", "Trasporre in 12 tonalità"], a: 1, fb: "La trasformazione melodico-armonica conserva il contorno melodico riconoscibile ma cambia gli accordi sottostanti. La melodia Do–Mi–Sol suonerà diversamente su I (DoMag7) che su VI (Lam7). La melodia crea coerenza; l'armonia rinnova l'espressione." },
{ q: "Che cos'è un periodo musicale?", opts: ["Una frase di 4 misure", "Una struttura in due frasi: antecedente (cadenza debole) + conseguente (cadenza forte)", "Un gruppo di 3 frasi", "Una sezione di 32 misure"], a: 1, fb: "Il periodo è binario: l'antecedente (frase 1) termina su una cadenza debole (spesso V — semicadenza), creando una domanda. Il conseguente (frase 2) termina su una cadenza forte (I — cadenza perfetta), portando la risposta. Lunghezza tipica: 16 misure (8+8)." },
{ q: "L'antecedente di un periodo termina su:", opts: ["La tonica (I) — cadenza perfetta", "La dominante (V) — semicadenza, effetto di domanda sospesa", "La sottodominante (IV)", "La mediante (III)"], a: 1, fb: "L'antecedente termina su V (semicadenza) — l'orecchio attende una conclusione. È la 'domanda'. Il conseguente risponde terminando su I. Questo schema domanda/risposta è la struttura retorica fondamentale della musica tonale." },
{ q: "Il conseguente di un periodo termina su:", opts: ["La dominante (V)", "La tonica (I) — cadenza perfetta, conclusione", "La sottodominante (IV)", "Un accordo di settima"], a: 1, fb: "Il conseguente termina su I (cadenza perfetta). Dopo la 'domanda' dell'antecedente (che finisce su V), il conseguente porta la 'risposta' conclusiva ancorandosi alla tonica. È la retorica musicale più naturale." },
{ q: "La differenza principale tra una frase e un periodo è:", opts: ["Solo la lunghezza", "La frase = un'unità autonoma (8 mis.) con la sua cadenza; il periodo = due frasi (antecedente + conseguente, 16 mis.) con cadenza debole poi forte", "Il numero di motivi", "La tonalità"], a: 1, fb: "La frase è un'unità autonoma (tipicamente 8 misure) con la propria cadenza. Il periodo è una struttura di due frasi: antecedente (cadenza V — domanda) + conseguente (cadenza I — risposta). Il periodo ha quindi tipicamente 16 misure." },
{ q: "Antecedente e conseguente condividono spesso:", opts: ["Esattamente le stesse note", "Lo stesso materiale tematico di partenza — legati dallo stesso motivo iniziale, ma conclusi diversamente", "Lo stesso tempo", "Assolutamente la stessa durata"], a: 1, fb: "Antecedente e conseguente iniziano spesso con lo stesso motivo — è ciò che li unisce in un periodo coerente. Ma le loro conclusioni differiscono: cadenza V (antecedente) vs cadenza I (conseguente). Stesso inizio, conclusioni contrastanti: domanda/risposta." },
{ q: "L'effetto di 'domanda/risposta' in un periodo è creato da:", opts: ["Due motivi diversi", "La cadenza debole dell'antecedente (V) che crea l'attesa, risolta dalla cadenza forte del conseguente (I)", "Il cambiamento di tempo", "L'aumento del volume"], a: 1, fb: "V (semicadenza) = domanda sospesa. I (cadenza perfetta) = risposta conclusiva. Questo schema domanda/risposta alla scala del periodo riflette la stessa logica della tensione/risoluzione alla scala dell'accordo (tritono di V7 → risoluzione verso I). Stesso principio, scala più grande." },
{ q: "Che cos'è la forma ABA?", opts: ["3 sezioni identiche", "Sezione A (principale) — sezione B contrastante — ritorno di A", "A ripetuto due volte poi B", "Una forma di 32 misure"], a: 1, fb: "La forma ABA (lied) presenta A (tema principale), B contrastante (nuova tonalità o modo), poi il ritorno di A. La simmetria A–B–A crea equilibrio e soddisfazione: si parte, si ritorna. Onnipresente nei Notturni di Chopin e nelle arie d'opera." },
{ q: "La forma AABA di 32 misure è:", opts: ["4 sezioni identiche", "A (8 mis.) ripetuto 2 volte, ponte B (8 mis.) contrastante, ritorno di A (8 mis.)", "A ripetuto 4 volte", "Una forma esclusivamente classica"], a: 1, fb: "AABA = 32 misure: A (8) + A (8) + B ponte (8) + A (8). Il ponte B è spesso in una tonalità vicina o con un ritmo armonico diverso. È la forma standard degli standard jazz americani degli anni 1930–60." },
{ q: "Nella forma AABA, la sezione B è chiamata:", opts: ["Coda", "Ponte (bridge)", "Ritornello", "Sviluppo"], a: 1, fb: "La sezione B in una forma AABA è il 'ponte' (bridge). Contrasta con A per tonalità, ritmo armonico o texture. Il ponte crea la varietà necessaria prima dell'ultimo ritorno di A — 'si ritorna a casa'." },
{ q: "Autumn Leaves utilizza quale forma?", opts: ["ABA", "AABA", "ABAB", "Blues 12 misure"], a: 1, fb: "Autumn Leaves (Kosma, 1945) è in forma AABA di 32 misure. È uno degli standard più suonati per insegnare la forma jazz — i suoi due II–V–I successivi (maggiore e minore) nella sezione A ne fanno anche un esempio di progressione tipica." },
{ q: "Il blues su 12 misure è strutturato attorno a:", opts: ["Solo I–V–I", "I7 (4 mis.) – IV7 (2 mis.) – I7 (2 mis.) – II–V–I (4 mis.)", "16 misure uguali", "Due sezioni di 6 misure"], a: 1, fb: "Blues 12 misure: I7 (4 mis.) | IV7 (2 mis.) | I7 (2 mis.) | turnaround (4 mis.). Struttura domanda/risposta/risoluzione alla scala di 12 misure. Forma prevedibile la cui stabilità libera l'improvvisatore." },
{ q: "La forma sonata comprende:", opts: ["Un solo tema sviluppato", "Esposizione (temi A+B), Sviluppo, Riesposizione", "Solo Introduzione e Coda", "4 sezioni di 8 misure"], a: 1, fb: "Forma sonata: Esposizione = tema A (tonica) + tema B (dominante/relativo); Sviluppo = manipolazione tematica in tonalità lontane; Riesposizione = A e B in tonica. La forma più teleologica del classicismo." },
{ q: "Nella forma sonata, lo 'sviluppo' si caratterizza per:", opts: ["La ripetizione dell'esposizione", "La manipolazione tematica — frammentare, modulare — in tonalità lontane", "L'introduzione di nuovi temi", "La conclusione del brano"], a: 1, fb: "Lo sviluppo è la sezione più instabile. I temi dell'esposizione vengono frammentati, trasformati, trasposti in tonalità lontane — è il 'viaggio' tra l'esposizione (partenza) e la riesposizione (ritorno). Beethoven eccelle nell'arte dello sviluppo." },
{ q: "Perché la forma crea il senso musicale?", opts: ["Perché determina la durata", "Perché organizza il tempo — senza forma, una successione di accordi è solo un elenco senza direzione né senso", "Perché fissa il tempo", "Perché indica la strumentazione"], a: 1, fb: "La forma dà una direzione al discorso musicale. Senza forma, una successione di accordi è 'senza radici' — non si sa né da dove si viene né dove si va. La forma crea l'attesa (tensione) e la sua risoluzione (soddisfazione): è la retorica della musica." },
{ q: "La forma strofa-ritornello è:", opts: ["Identica alla forma sonata", "Alternanza tra strofe (contenuto narrativo variabile) e ritornello (melodia ricorrente identica)", "Tre sezioni identiche", "Una forma esclusivamente strumentale"], a: 1, fb: "Strofa-ritornello: le strofe narrano (testo e a volte melodia variabili); il ritornello torna con lo stesso testo e la stessa melodia. Forma dominante della canzone popolare (pop, rock, folk). Combina varietà (strofe) e ricorrenza memorabile (ritornello)." },
{ q: "La forma rondò è:", opts: ["Solo ABA", "Un tema A che ritorna alternativamente tra episodi contrastanti: ABACADA...", "Una forma jazz di 32 misure", "Due sezioni di sviluppo"], a: 1, fb: "Il rondò alterna un ritornello (tema A) con episodi contrastanti (B, C, D...). Il tema A (spesso memorabile) ritorna come ancoraggio tra avventure musicali contrastanti. Molto presente nei finali di sonate classiche." },
{ q: "Schoenberg ha formalizzato la nozione di frase musicale in:", opts: ["Die Kunst der Fuge", "Fundamentals of Musical Composition (redatto negli anni 1930–40)", "Il Clavicembalo ben temperato", "Trattato di orchestrazione di Berlioz"], a: 1, fb: "Arnold Schoenberg ha redatto Fundamentals of Musical Composition negli anni 1930–40 all'UCLA, pubblicato postumo nel 1967. Questo trattato pedagogico analizza sistematicamente la frase, il motivo, il periodo e le grandi forme — riferimento fondamentale per l'insegnamento della composizione." },
{ q: "Schoenberg distingue due tipi di marce musicali:", opts: ["Marcia lenta e marcia rapida", "Marcia tonale (diatonica) e marcia reale (trasposizione stretta, a volte cromatica)", "Marcia ascendente e discendente", "Marcia semplice e doppia"], a: 1, fb: "Marcia tonale: il motivo si adatta agli intervalli della scala diatonica. Marcia reale: trasposizione stretta dello stesso identico intervallo (può uscire dalla scala). Questa distinzione è centrale nell'analisi di Schoenberg — i due tipi hanno effetti espressivi molto diversi." },
{ q: "Il concetto di 'liquidazione' in Schoenberg designa:", opts: ["La soppressione di accordi", "L'eliminazione progressiva delle caratteristiche distintive del motivo alla fine della frase per segnalare la cadenza", "Un cambio di tonalità", "La riduzione del numero delle voci"], a: 1, fb: "La liquidazione è il processo attraverso il quale un motivo perde progressivamente i suoi tratti distintivi alla fine della frase. Si conserva il ritmo, poi solo il contorno, poi quasi nulla — la frase si dissolve nella cadenza. Procedimento retorico di 'conclusione' molto sofisticato." },
{ q: "Secondo Schoenberg, la ripetizione nella composizione musicale serve a:", opts: ["Allungare un brano senza sforzo", "Stabilire la coerenza — l'ascoltatore riconosce ciò che ha già sentito e può seguire il discorso musicale", "Compensare la mancanza di idee", "Soddisfare le convenzioni del genere"], a: 1, fb: "Schoenberg insiste sulla ripetizione come strumento di coerenza (Verständlichkeit). Un motivo ripetuto (anche trasformato) è riconoscibile. La ripetizione crea il senso di un'idea sviluppata piuttosto che una successione di idee disparate — è la 'comprensibilità' musicale." },
{ q: "Schoenberg è paradossalmente anche famoso per:", opts: ["Aver inventato la tonalità", "Aver sviluppato il dodecafonismo — composizione con i 12 semitoni su base di uguaglianza, senza tonalità centrale", "Aver composto solo jazz", "Aver scritto opere barocche"], a: 1, fb: "Schoenberg è il teorico della frase tonale E il fondatore del dodecafonismo (metodo dei 12 suoni, 1921). Paradosso: il suo trattato analizza la forma tonale, ma la sua musica (Pierrot Lunaire, Suite op.25) abolisce la tonalità. È il ponte tra tradizione e rottura." },
{ q: "Cosa distingue una progressione 'senza radici' da una vera frase musicale?", opts: ["Il numero di accordi", "La frase ha un motivo direttore, una struttura a fasi e una cadenza — la progressione 'senza radici' non ha né direzione né conclusione", "La tonalità", "Il tempo"], a: 1, fb: "Una progressione 'senza radici' = accordi incatenati senza logica motivica né cadenza premeditata. Una frase musicale = motivo + sviluppo in 4 fasi + cadenza. La differenza è quella tra una conversazione (discorso strutturato) e un elenco di parole (assenza di discorso)." },
{ q: "Come si riconosce una cadenza in una frase musicale?", opts: ["Per un silenzio", "Per un riposo su V (semicadenza) o I (cadenza perfetta) — momento di risoluzione della tensione armonica", "Per un cambio di tempo", "Per una nota più acuta"], a: 1, fb: "La cadenza è un momento di riposo armonico. Semicadenza (V): domanda sospesa. Cadenza perfetta (I): risoluzione completa. Cadenza plagale (IV–I): conclusione dolce. Cadenza ingannevole (V→VI): risoluzione ingannevole. Ogni tipo crea un diverso effetto di punteggiatura." },
{ q: "In uno standard jazz in forma AABA, il ponte (B) serve a:", opts: ["Ripetere A", "Creare un contrasto armonico e melodico che rende il ritorno di A tanto più soddisfacente", "Concludere il brano", "Introdurre solo il solista"], a: 1, fb: "Il ponte crea un contrasto — spesso in una tonalità vicina, con un ritmo armonico o una direzione melodica opposta ad A. Questo contrasto rende l'ultimo ritorno di A più atteso e più soddisfacente — 'si ritorna a casa'. È la dialettica tensione/risoluzione alla scala formale." },
{ q: "La Sonata Patetica di Beethoven è un esempio classico della frase di 8 misure perché:", opts: ["Dura 8 minuti", "Il suo primo tema illustra le 4 fasi: idea di base, ripetizione, accelerazione (liquidazione), cadenza", "Ha solo 8 misure", "Schoenberg l'ha analizzata nel suo trattato"], a: 1, fb: "Il primo tema dell'Allegro della Patetica (op.13, 1798) illustra le 4 fasi: motivo distintivo (mis. 1–2), ripetizione trasformata (mis. 3–4), accelerazione con liquidazione (mis. 5–7), cadenza (mis. 8). Esempio pedagogico perfetto citato regolarmente nei trattati di analisi." },
{ q: "Come sono collegate marcia armonica e marcia melodica?", opts: ["Sono sempre opposte", "La marcia melodica ripete un motivo ad altezze successive; la marcia armonica sostiene queste altezze con accordi che progrediscono nella stessa direzione", "Sono sempre indipendenti", "La marcia armonica precede sempre la melodia"], a: 1, fb: "In una marcia, melodia e armonia avanzano insieme: melodia Do–Mi–Sol, Re–Fa–La, Mi–Sol–Si (marcia melodica ascendente) su accordi I, II, III (marcia armonica ascendente). Entrambe le dimensioni si muovono in parallelo — è ciò che crea l'effetto di progressione sostenuta." },
{ q: "Perché il blues su 12 misure è considerato una forma musicale?", opts: ["Perché dura sempre 12 secondi", "Perché ha una struttura ripetibile e prevedibile (I7–IV7–I7–V7–I7) che crea attese e risoluzioni ad ogni ciclo", "Perché contiene solo 3 accordi", "Perché proviene dal Delta del Mississippi"], a: 1, fb: "Il blues su 12 misure è una forma perché la sua struttura è prevedibile e condivisa da musicisti e ascoltatori. Questa prevedibilità è una risorsa: l'improvvisatore può suonare 'contro' la forma (contro le aspettative) o 'con' essa (confermandole). La forma = quadro del discorso musicale." },
{ q: "Qual è la lunghezza tipica di una frase musicale nel repertorio classico e jazz?", opts: ["4 misure", "8 misure", "12 misure", "16 misure"], a: 1, fb: "8 misure è la lunghezza standard della frase. Questa convenzione si è stabilita nel XVIII secolo ed è passata nel jazz (le sezioni A e B della forma AABA hanno ciascuna 8 misure). Il periodo (antecedente + conseguente) ha quindi tipicamente 16 misure (8+8)." },
{ q: "Che cos'è un 'tema' rispetto a un 'motivo'?", opts: ["Un tema è più breve di un motivo", "Il motivo è l'elemento più piccolo; il tema è un'idea più sviluppata (spesso una frase intera) costruita da uno o più motivi", "Un tema è armonico, un motivo è melodico", "Sono sinonimi esatti"], a: 1, fb: "Motivo = cellula minima (4 note). Tema = idea musicale sviluppata (spesso 8–16 misure) costruita da uno o più motivi. Il tema è memorabile e 'cantabile'; il motivo è il 'germe' generatore. Beethoven trae grandi temi da un solo motivo di 4 note." },
{ q: "Nella forma sonata classica, l'esposizione presenta generalmente:", opts: ["Un solo tema", "Due temi contrastanti — tema A (tonica) e tema B (dominante o relativo minore)", "Quattro temi", "Solo lo sviluppo"], a: 1, fb: "L'esposizione presenta due temi: A (tonica, spesso energico) e B (dominante se maggiore, relativo se minore — spesso più lirico). Questo contrasto A/B crea la 'tensione drammatica' che sviluppo e riesposizione esploreranno e risolveranno." },
{ q: "Un 'motivo ricorrente' in una grande forma (leitmotiv, idée fixe) serve a:", opts: ["Ripetere un passaggio in modo meccanico", "Creare un'unità su grande scala — il motivo riappare in momenti chiave per tessere la coerenza di tutta l'opera", "Facilitare la memorizzazione del musicista", "Indicare una modulazione"], a: 1, fb: "Il motivo ricorrente crea coerenza su grande scala. Wagner usa i Leitmotive associati a personaggi che ritornano per tutta un'opera. Berlioz inventa l'idée fixe (Sinfonia Fantastica). È la logica della forma ABA estesa alla scala di un'opera intera." },
{ q: "La forma ABAC è particolarmente usata in:", opts: ["Il blues", "All The Things You Are, My Romance — standard con due seconde volte diverse (B poi C)", "La sinfonia classica", "Il rondò"], a: 1, fb: "ABAC: A ritorna due volte ma la seconda volta finisce in modo diverso (C invece di B). All The Things You Are (Kern, 1939) è l'esempio più celebre. Ogni ritorno di A è leggermente diverso nella sua conclusione — leggera sorpresa nonostante la ricorrenza." },
{ q: "Perché capire la forma è utile per un improvvisatore jazz?", opts: ["Per rispettare le convenzioni", "Per sapere dove si è nella griglia — inizio o fine di A, ponte B, ritorno finale — e adattare il proprio gioco di conseguenza", "Per leggere la partitura", "Per suonare più note"], a: 1, fb: "Un improvvisatore che conosce la forma suona 'con' la struttura: più tensione al ponte (B), risoluzione più marcata al ritorno di A, climax nel momento giusto. Ignorare la forma equivale a improvvisare 'nel vuoto' — tecnicamente corretto ma musicalmente inespressivo." },
];

const questionsPt: Question[] = [
{ q: "O que é um motivo musical?", opts: ["Um acorde de 4 sons", "O menor elemento musical distintivo — fio condutor do discurso de uma frase", "Uma escala completa", "Um acorde de dominante"], a: 1, fb: "O motivo é o menor elemento musical reconhecível e estruturante. Contém a identidade rítmica e/ou melódica que será repetida e transformada. Beethoven constrói toda a sua 5ª Sinfonia a partir de um motivo de apenas 4 notas (Sol–Sol–Sol–Mib)." },
{ q: "O motivo da 5ª Sinfonia de Beethoven (Sol–Sol–Sol–Mib) ilustra que:", opts: ["Um motivo deve ser longo para ser expressivo", "Um motivo extremamente curto pode gerar um discurso musical completo por repetição e transformação", "A 5ª utiliza um modo menor exclusivamente", "Este motivo vem de uma canção popular"], a: 1, fb: "Sol–Sol–Sol–Mib: 4 notas, 3 repetidas + uma queda de terça. Este motivo é o germe de toda a 5ª Sinfonia (1808). Beethoven o fragmenta, o transpõe, o aumenta — demonstrando que um motivo mínimo pode construir vinte minutos de música." },
{ q: "Qual é a diferença entre 'música de suporte' e 'música de discurso'?", opts: ["A música de suporte é mais longa", "A música de suporte acompanha uma ação exterior; a música de discurso desenvolve as suas próprias ideias musicais de forma autónoma", "A música de discurso é mais curta", "Não há nenhuma diferença"], a: 1, fb: "A música de suporte (cinema, ballet) serve uma ação exterior — a sua estrutura pode ser fragmentada segundo a narração. A música de discurso (sonata, fuga, standard jazz) desenvolve as suas próprias ideias de forma lógica e autónoma, independentemente de qualquer contexto extra-musical." },
{ q: "O fio condutor de uma frase musical é:", opts: ["A tonalidade", "O motivo — repetido e transformado para dar coerência à frase", "O tempo", "O acompanhamento"], a: 1, fb: "O motivo é o fio condutor. A sua repetição (estrita ou transformada) cria coerência. O ouvinte reconhece o motivo mesmo transformado — é o que dá a impressão de um discurso musical contínuo em vez de uma sucessão de ideias díspares." },
{ q: "Quantas fases tem uma frase musical típica de 8 compassos?", opts: ["2", "3", "4", "8"], a: 2, fb: "A frase de 8 compassos segue 4 fases: (1) ideia de base, (2) repetição, (3) aceleração/fragmentação, (4) cadência. Este esquema está presente em Beethoven, Mozart, Haydn e na maioria das formas jazz standard." },
{ q: "Qual é a primeira fase de uma frase musical?", opts: ["A cadência", "A ideia de base — apresentação do motivo principal", "A repetição", "A liquidação"], a: 1, fb: "A ideia de base é o enunciado do 'sujeito' da frase: apresentação do motivo ou da célula motivica. As 3 fases seguintes (repetição, aceleração, cadência) derivam desta ideia inicial." },
{ q: "O que é a 'liquidação' de uma frase (termo de Schoenberg)?", opts: ["Repetir o motivo mais lentamente", "Acelerar o ritmo harmónico no final da frase — as harmonias mudam mais rapidamente para sinalizar a cadência iminente", "Reduzir o número de instrumentos", "Tocar mais suavemente"], a: 1, fb: "A liquidação designa a aceleração do ritmo harmónico no final da frase. As harmonias que mudavam de 2 em 2 compassos mudam agora de compasso em compasso, depois a cada tempo — sinal retórico de que a cadência se aproxima: 'a conclusão está a chegar'." },
{ q: "Na 3ª fase de uma frase de Beethoven, a aceleração manifesta-se por:", opts: ["Um tempo mais rápido", "Motivos fragmentados e um ritmo harmónico mais denso, criando tensão antes da cadência", "Uma mudança de instrumento", "Uma melodia mais grave"], a: 1, fb: "A aceleração da 3ª fase = fragmentação do motivo e densificação do ritmo harmónico. Beethoven repete fragmentos de motivo cada vez mais curtos, os acordes mudam cada vez mais rápido — tensão que 'chama' a cadência final." },
{ q: "O que é a 'repetição estrita' de um motivo?", opts: ["Repetir noutra tonalidade", "Repetir o motivo de forma idêntica — mesmas alturas, mesmo ritmo", "Repetir com ornamentos", "Repetir apenas na oitava inferior"], a: 1, fb: "A repetição estrita reproduz o motivo exatamente. A técnica mais direta: o ouvinte reconhece imediatamente o motivo. Pode parecer mecânica; é por isso que é frequentemente combinada com outras técnicas de transformação." },
{ q: "A 'transformação melódica' de um motivo consiste em:", opts: ["Mudar o seu ritmo", "Transpor o motivo para outra altura mantendo o mesmo contorno rítmico", "Inverter os intervalos", "Tocar o motivo ao contrário"], a: 1, fb: "A transformação melódica transpõe o motivo — o contorno rítmico permanece idêntico, as alturas mudam. Dó–Mi–Sol torna-se Ré–Fá–Lá (um tom mais alto). A identidade rítmica mantém a coerência; a nova altura traz variedade." },
{ q: "Uma 'marcha' (ou sequência) musical é:", opts: ["Um ritmo de marcha militar", "Um motivo repetido em graus sucessivos da escala ou por transposição cromática", "Um acorde de passagem", "Uma forma de 16 compassos"], a: 1, fb: "A marcha (sequência) repete um motivo em alturas sucessivas. Marcha tonal: permanece na escala diatónica. Marcha real (cromática): transpõe estritamente o mesmo intervalo (pode sair da escala). Ex. Dó–Mi–Sol, Ré–Fá–Lá, Mi–Sol–Si (marcha tonal ascendente)." },
{ q: "A diferença entre 'marcha tonal' e 'marcha real' é:", opts: ["O tempo", "A marcha tonal permanece diatónica (intervalos ligeiramente ajustados); a marcha real transpõe estritamente o mesmo intervalo, criando cromatismos", "A marcha real é mais longa", "Não há nenhuma diferença"], a: 1, fb: "Distinção chave de Schoenberg: marcha tonal = o motivo adapta-se aos intervalos da escala (pode mudar ligeiramente de intervalo); marcha real = transposição estrita do mesmo intervalo (pode introduzir notas estranhas à escala)." },
{ q: "Um motivo 'complementar' é:", opts: ["Um motivo que imita o principal em uníssono", "Um segundo motivo que responde ao primeiro, completando o espaço rítmico ou melódico da frase", "Um motivo invertido", "Um motivo tocado simultaneamente"], a: 1, fb: "O motivo complementar responde ao motivo principal — frequentemente nos compassos seguintes. Ex. Motivo A (compassos 1–2) + Motivo B (compassos 3–4). Juntos, A e B formam a frase completa; cada um é incompleto sem o outro." },
{ q: "A 'transformação melódico-harmónica' consiste em:", opts: ["Mudar o ritmo e a melodia", "Manter o contorno melódico do motivo mas mudar os acordes por baixo, modificando a cor harmónica", "Inverter a melodia e os acordes", "Transpor em 12 tonalidades"], a: 1, fb: "A transformação melódico-harmónica conserva o contorno melódico reconhecível mas muda os acordes por baixo. A melodia Dó–Mi–Sol soará diferente sobre I (DóMaj7) do que sobre VI (Lam7). A melodia cria coerência; a harmonia renova a expressão." },
{ q: "O que é um período musical?", opts: ["Uma frase de 4 compassos", "Uma estrutura em duas frases: antecedente (cadência fraca) + consequente (cadência forte)", "Um grupo de 3 frases", "Uma secção de 32 compassos"], a: 1, fb: "O período é binário: o antecedente (frase 1) termina numa cadência fraca (frequentemente V — meia-cadência), criando uma pergunta. O consequente (frase 2) termina numa cadência forte (I — cadência perfeita), trazendo a resposta. Duração típica: 16 compassos (8+8)." },
{ q: "O antecedente de um período termina em:", opts: ["A tónica (I) — cadência perfeita", "A dominante (V) — meia-cadência, efeito de pergunta suspensa", "A subdominante (IV)", "A mediante (III)"], a: 1, fb: "O antecedente termina em V (meia-cadência) — o ouvido aguarda uma conclusão. É a 'pergunta'. O consequente responde terminando em I. Este esquema pergunta/resposta é a estrutura retórica fundamental da música tonal." },
{ q: "O consequente de um período termina em:", opts: ["A dominante (V)", "A tónica (I) — cadência perfeita, conclusão", "A subdominante (IV)", "Um acorde de sétima"], a: 1, fb: "O consequente termina em I (cadência perfeita). Após a 'pergunta' do antecedente (que termina em V), o consequente traz a 'resposta' conclusiva ancorando-se na tónica. É a retórica musical mais natural." },
{ q: "A diferença principal entre uma frase e um período é:", opts: ["Apenas a duração", "A frase = uma unidade autónoma (8 comp.) com a sua cadência; o período = duas frases (antecedente + consequente, 16 comp.) com cadência fraca depois forte", "O número de motivos", "A tonalidade"], a: 1, fb: "A frase é uma unidade autónoma (tipicamente 8 compassos) com a sua própria cadência. O período é uma estrutura de duas frases: antecedente (cadência V — pergunta) + consequente (cadência I — resposta). O período tem portanto tipicamente 16 compassos." },
{ q: "Antecedente e consequente partilham frequentemente:", opts: ["Exatamente as mesmas notas", "O mesmo material temático de partida — ligados pelo mesmo motivo inicial, mas concluídos de forma diferente", "O mesmo tempo", "Absolutamente a mesma duração"], a: 1, fb: "Antecedente e consequente começam frequentemente com o mesmo motivo — é o que os une num período coerente. Mas as suas conclusões diferem: cadência V (antecedente) vs. cadência I (consequente). Mesmo início, conclusões contrastantes: pergunta/resposta." },
{ q: "O efeito de 'pergunta/resposta' num período é criado por:", opts: ["Dois motivos diferentes", "A cadência fraca do antecedente (V) que cria a expectativa, resolvida pela cadência forte do consequente (I)", "A mudança de tempo", "O aumento do volume"], a: 1, fb: "V (meia-cadência) = pergunta suspensa. I (cadência perfeita) = resposta conclusiva. Este esquema pergunta/resposta à escala do período reflete a mesma lógica que a tensão/resolução à escala do acorde (trítono de V7 → resolução para I). Mesmo princípio, escala maior." },
{ q: "O que é a forma ABA?", opts: ["3 secções idênticas", "Secção A (principal) — secção B contrastante — retorno de A", "A repetido duas vezes depois B", "Uma forma de 32 compassos"], a: 1, fb: "A forma ABA (lied) apresenta A (tema principal), B contrastante (nova tonalidade ou modo), depois o retorno de A. A simetria A–B–A cria equilíbrio e satisfação: parte-se, regressa-se. Omnipresente nos Noturnos de Chopin e nas árias de ópera." },
{ q: "A forma AABA de 32 compassos é:", opts: ["4 secções idênticas", "A (8 comp.) repetido 2 vezes, ponte B (8 comp.) contrastante, retorno de A (8 comp.)", "A repetido 4 vezes", "Uma forma exclusivamente clássica"], a: 1, fb: "AABA = 32 compassos: A (8) + A (8) + B ponte (8) + A (8). A ponte B está frequentemente numa tonalidade vizinha ou com um ritmo harmónico diferente. É a forma standard dos standards jazz americanos dos anos 1930–60." },
{ q: "Na forma AABA, a secção B é chamada:", opts: ["Coda", "Ponte (bridge)", "Refrão", "Desenvolvimento"], a: 1, fb: "A secção B numa forma AABA é a 'ponte' (bridge). Contrasta com A pela tonalidade, ritmo harmónico ou textura. A ponte cria a variedade necessária antes do último retorno de A — 'regressa-se a casa'." },
{ q: "Autumn Leaves utiliza que forma?", opts: ["ABA", "AABA", "ABAB", "Blues 12 compassos"], a: 1, fb: "Autumn Leaves (Kosma, 1945) está em forma AABA de 32 compassos. É um dos standards mais tocados para ensinar a forma jazz — os seus dois II–V–I sucessivos (maior e menor) na secção A tornam-no também num exemplo de progressão típica." },
{ q: "O blues de 12 compassos está estruturado em torno de:", opts: ["Apenas I–V–I", "I7 (4 comp.) – IV7 (2 comp.) – I7 (2 comp.) – II–V–I (4 comp.)", "16 compassos iguais", "Duas secções de 6 compassos"], a: 1, fb: "Blues 12 compassos: I7 (4 comp.) | IV7 (2 comp.) | I7 (2 comp.) | turnaround (4 comp.). Estrutura pergunta/resposta/resolução à escala de 12 compassos. Forma previsível cuja estabilidade liberta o improvisador." },
{ q: "A forma sonata compreende:", opts: ["Um único tema desenvolvido", "Exposição (temas A+B), Desenvolvimento, Reexposição", "Apenas Introdução e Coda", "4 secções de 8 compassos"], a: 1, fb: "Forma sonata: Exposição = tema A (tónica) + tema B (dominante/relativo); Desenvolvimento = manipulação temática em tonalidades distantes; Reexposição = A e B em tónica. A forma mais teleológica do classicismo." },
{ q: "Na forma sonata, o 'desenvolvimento' caracteriza-se por:", opts: ["A repetição da exposição", "A manipulação temática — fragmentar, modular — em tonalidades distantes", "A introdução de novos temas", "A conclusão do brano"], a: 1, fb: "O desenvolvimento é a secção mais instável. Os temas da exposição são fragmentados, transformados, transpostos em tonalidades distantes — é a 'viagem' entre a exposição (partida) e a reexposição (regresso). Beethoven é excelente na arte do desenvolvimento." },
{ q: "Por que a forma cria o sentido musical?", opts: ["Porque determina a duração", "Porque organiza o tempo — sem forma, uma sucessão de acordes é apenas uma lista sem direção nem sentido", "Porque fixa o tempo", "Porque indica a instrumentação"], a: 1, fb: "A forma dá uma direção ao discurso musical. Sem forma, uma sucessão de acordes está 'sem raízes' — não se sabe de onde se vem nem para onde se vai. A forma cria a expectativa (tensão) e a sua resolução (satisfação): é a retórica da música." },
{ q: "A forma verso-refrão é:", opts: ["Idêntica à forma sonata", "Alternância entre versos (conteúdo narrativo variável) e refrão (melodia recorrente idêntica)", "Três secções idênticas", "Uma forma exclusivamente instrumental"], a: 1, fb: "Verso-refrão: os versos narram (texto e às vezes melodia variáveis); o refrão regressa com o mesmo texto e a mesma melodia. Forma dominante da canção popular (pop, rock, folk). Combina variedade (versos) e recorrência memorável (refrão)." },
{ q: "A forma rondó é:", opts: ["Apenas ABA", "Um tema A que regressa alternadamente entre episódios contrastantes: ABACADA...", "Uma forma jazz de 32 compassos", "Duas secções de desenvolvimento"], a: 1, fb: "O rondó alterna um refrão (tema A) com episódios contrastantes (B, C, D...). O tema A (frequentemente memorável) regressa como âncora entre aventuras musicais contrastantes. Muito presente nos finais de sonatas clássicas." },
{ q: "Schoenberg formalizou a noção de frase musical em:", opts: ["Die Kunst der Fuge", "Fundamentals of Musical Composition (redigido nos anos 1930–40)", "O Cravo Bem Temperado", "Tratado de orquestração de Berlioz"], a: 1, fb: "Arnold Schoenberg redigiu Fundamentals of Musical Composition nos anos 1930–40 na UCLA, publicado postumamente em 1967. Este tratado pedagógico analisa sistematicamente a frase, o motivo, o período e as grandes formas — referência fundamental para o ensino da composição." },
{ q: "Schoenberg distingue dois tipos de marchas musicais:", opts: ["Marcha lenta e marcha rápida", "Marcha tonal (diatónica) e marcha real (transposição estrita, por vezes cromática)", "Marcha ascendente e descendente", "Marcha simples e dupla"], a: 1, fb: "Marcha tonal: o motivo adapta-se aos intervalos da escala diatónica. Marcha real: transposição estrita do mesmo intervalo exato (pode sair da escala). Esta distinção é central na análise de Schoenberg — os dois tipos têm efeitos expressivos muito diferentes." },
{ q: "O conceito de 'liquidação' em Schoenberg designa:", opts: ["A supressão de acordes", "A eliminação progressiva das características distintivas do motivo no final da frase para sinalizar a cadência", "Uma mudança de tonalidade", "A redução do número de vozes"], a: 1, fb: "A liquidação é o processo pelo qual um motivo perde progressivamente os seus traços distintivos no final da frase. Conserva-se o ritmo, depois apenas o contorno, depois quase nada — a frase dissolve-se na cadência. Procedimento retórico de 'conclusão' muito sofisticado." },
{ q: "Segundo Schoenberg, a repetição na composição musical serve para:", opts: ["Alongar um brano sem esforço", "Estabelecer a coerência — o ouvinte reconhece o que já ouviu e pode seguir o discurso musical", "Compensar a falta de ideias", "Satisfazer as convenções do género"], a: 1, fb: "Schoenberg insiste na repetição como ferramenta de coerência (Verständlichkeit). Um motivo repetido (mesmo transformado) é reconhecível. A repetição cria o sentido de uma ideia desenvolvida em vez de uma sucessão de ideias díspares — é a 'compreensibilidade' musical." },
{ q: "Schoenberg é paradoxalmente também famoso por:", opts: ["Ter inventado a tonalidade", "Ter desenvolvido o dodecafonismo — composição com os 12 semitons em igualdade, sem tonalidade central", "Ter composto exclusivamente jazz", "Ter escrito óperas barrocas"], a: 1, fb: "Schoenberg é o teórico da frase tonal E o fundador do dodecafonismo (método dos 12 sons, 1921). Paradoxo: o seu tratado analisa a forma tonal, mas a sua música (Pierrot Lunaire, Suite op.25) abole a tonalidade. É a ponte entre tradição e ruptura." },
{ q: "O que distingue uma progressão 'sem raízes' de uma verdadeira frase musical?", opts: ["O número de acordes", "A frase tem um motivo condutor, uma estrutura de fases e uma cadência — a progressão 'sem raízes' não tem nem direção nem conclusão", "A tonalidade", "O tempo"], a: 1, fb: "Uma progressão 'sem raízes' = acordes encadeados sem lógica motivica nem cadência premeditada. Uma frase musical = motivo + desenvolvimento em 4 fases + cadência. A diferença é a que existe entre uma conversa (discurso estruturado) e uma lista de palavras (ausência de discurso)." },
{ q: "Como se reconhece uma cadência numa frase musical?", opts: ["Por um silêncio", "Por um repouso em V (meia-cadência) ou I (cadência perfeita) — momento de resolução da tensão harmónica", "Por uma mudança de tempo", "Por uma nota mais aguda"], a: 1, fb: "A cadência é um momento de repouso harmónico. Meia-cadência (V): pergunta suspensa. Cadência perfeita (I): resolução completa. Cadência plagal (IV–I): conclusão suave. Cadência interrompida (V→VI): resolução enganosa. Cada tipo cria um efeito de pontuação diferente." },
{ q: "Num standard jazz em forma AABA, a ponte (B) serve para:", opts: ["Repetir A", "Criar um contraste harmónico e melódico que torna o retorno de A ainda mais satisfatório", "Concluir o brano", "Introduzir apenas o solista"], a: 1, fb: "A ponte cria um contraste — frequentemente numa tonalidade vizinha, com um ritmo harmónico ou uma direção melódica oposta a A. Este contraste torna o último retorno de A mais esperado e mais satisfatório — 'regressa-se a casa'. É a dialética tensão/resolução à escala formal." },
{ q: "A Sonata Patética de Beethoven é um exemplo clássico da frase de 8 compassos porque:", opts: ["Dura 8 minutos", "O seu primeiro tema ilustra as 4 fases: ideia de base, repetição, aceleração (liquidação), cadência", "Tem apenas 8 compassos", "Schoenberg analisou-a no seu tratado"], a: 1, fb: "O primeiro tema do Allegro da Patética (op.13, 1798) ilustra as 4 fases: motivo distintivo (comp. 1–2), repetição transformada (comp. 3–4), aceleração com liquidação (comp. 5–7), cadência (comp. 8). Exemplo pedagógico perfeito regularmente citado nos tratados de análise." },
{ q: "Como estão relacionadas marcha harmónica e marcha melódica?", opts: ["Estão sempre opostas", "A marcha melódica repete um motivo em alturas sucessivas; a marcha harmónica suporta essas alturas com acordes que progridem na mesma direção", "Estão sempre independentes", "A marcha harmónica precede sempre a melodia"], a: 1, fb: "Numa marcha, melodia e harmonia avançam juntas: melodia Dó–Mi–Sol, Ré–Fá–Lá, Mi–Sol–Si (marcha melódica ascendente) sobre acordes I, II, III (marcha harmónica ascendente). As duas dimensões movem-se em paralelo — é o que cria o efeito de progressão sustentada." },
{ q: "Por que o blues de 12 compassos é considerado uma forma musical?", opts: ["Porque dura sempre 12 segundos", "Porque tem uma estrutura repetível e previsível (I7–IV7–I7–V7–I7) criando expectativas e resoluções a cada ciclo", "Porque contém apenas 3 acordes", "Porque vem do Delta do Mississippi"], a: 1, fb: "O blues de 12 compassos é uma forma porque a sua estrutura é previsível e partilhada por músicos e ouvintes. Esta previsibilidade é um recurso: o improvisador pode tocar 'contra' a forma (contra as expectativas) ou 'com' ela (confirmando-as). A forma = quadro do discurso musical." },
{ q: "Qual é a duração típica de uma frase musical no repertório clássico e jazz?", opts: ["4 compassos", "8 compassos", "12 compassos", "16 compassos"], a: 1, fb: "8 compassos é a duração standard da frase. Esta convenção estabeleceu-se no século XVIII e passou ao jazz (as secções A e B da forma AABA têm cada uma 8 compassos). O período (antecedente + consequente) tem portanto tipicamente 16 compassos (8+8)." },
{ q: "O que é um 'tema' em relação a um 'motivo'?", opts: ["Um tema é mais curto do que um motivo", "O motivo é o elemento mais pequeno; o tema é uma ideia mais desenvolvida (frequentemente uma frase inteira) construída a partir de um ou vários motivos", "Um tema é harmónico, um motivo é melódico", "São sinónimos exatos"], a: 1, fb: "Motivo = célula mínima (4 notas). Tema = ideia musical desenvolvida (frequentemente 8–16 compassos) construída a partir de um ou vários motivos. O tema é memorável e 'cantável'; o motivo é o 'germe' gerador. Beethoven extrai grandes temas de um único motivo de 4 notas." },
{ q: "Na forma sonata clássica, a exposição apresenta geralmente:", opts: ["Um único tema", "Dois temas contrastantes — tema A (tónica) e tema B (dominante ou relativo menor)", "Quatro temas", "Apenas o desenvolvimento"], a: 1, fb: "A exposição apresenta dois temas: A (tónica, frequentemente enérgico) e B (dominante se maior, relativo se menor — frequentemente mais lírico). Este contraste A/B cria a 'tensão dramática' que desenvolvimento e reexposição irão explorar e resolver." },
{ q: "Um 'motivo recorrente' numa grande forma (leitmotiv, idée fixe) serve para:", opts: ["Repetir uma passagem de forma mecânica", "Criar uma unidade em grande escala — o motivo reaparece em momentos chave para tecer a coerência de toda a obra", "Facilitar a memorização do músico", "Indicar uma modulação"], a: 1, fb: "O motivo recorrente cria coerência em grande escala. Wagner usa Leitmotive associados a personagens que reaparecem ao longo de uma ópera. Berlioz inventa a idée fixe (Sinfonia Fantástica). É a lógica da forma ABA estendida à escala de uma obra inteira." },
{ q: "A forma ABAC é notavelmente utilizada em:", opts: ["O blues", "All The Things You Are, My Romance — standards com duas segundas voltas diferentes (B depois C)", "A sinfonia clássica", "O rondó"], a: 1, fb: "ABAC: A regressa duas vezes mas termina de forma diferente na segunda vez (C em vez de B). All The Things You Are (Kern, 1939) é o exemplo mais célebre. Cada retorno de A é ligeiramente diferente na sua conclusão — ligeira surpresa apesar da recorrência." },
{ q: "Por que compreender a forma é útil para um improvisador jazz?", opts: ["Para respeitar as convenções", "Para saber onde se está na grelha — início ou fim de A, ponte B, retorno final — e adaptar o seu jogo em conformidade", "Para ler a partitura", "Para tocar mais notas"], a: 1, fb: "Um improvisador que conhece a forma toca 'com' a estrutura: mais tensão na ponte (B), resolução mais marcada no retorno de A, clímax no momento certo. Ignorar a forma equivale a improvisar 'no vazio' — tecnicamente correto mas musicalmente inexpressivo." },
];

